    ('f41351499afeac652b1fb177d366bda1e1d68b6e', 'TWK', 'wawasan-kebangsaan', 'sedang', 'draft', 'Dengan adanya prinsip otonomi seluas-luasnya, daerah diberi kewenangan mengatur urusan pemerintahannya sendiri, kecuali di bidang…', 'Agama', 'Perekonomian', 'Wilayah', 'Sosial Masyarakat', 'SDA', null, '2. SOAL LATIHAN TWK-TIU-TKP.txt', '20'),
