    ('0dfd939425efdfe165a932cf26456685a05b3ecc', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Pada tahun 2010 sebuah pabrik gula memproduksi gula pasir sebanyak ¾ ton. Jika kebijakan produksi untuk tahun 2011 dan 2012 ditetapkan kenaikannya sebesar 125% dari produksi tahun 2010, be rapa ton jumlah produksi gula pasir pabrik terebut dalam tiga tahun terakhir ini?', 'Tak dapat ditentukan', '196,48', '282,94', '479,42', '480,57', null, '2. SOAL LATIHAN TWK-TIU-TKP.txt', '47'),
    ('dae3928b5987f5f15f6abbb79affd38437036e6a', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Jika x adalah 27,8% dari 45 dan y adalah 45%b dari 27,8 maka ...', 'x > y', 'x < y', 'x =y', 'hubungan x dan y tidak dapat ditentukan', 'x ≠ y', null, '2. SOAL LATIHAN TWK-TIU-TKP.txt', '50'),
    ('53ef1ba466210411060a00897acca426486a6b17', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Jika p sembarang bilangan, {x = 3p 2+5} dan {y = 2p 2 + 4}, manakah pernyataan berikut yang benar?', 'x > y', 'x < y', 'x = y', 'hubungan x dan y tidak dapat di tentukan', 'x ≠ y', null, '2. SOAL LATIHAN TWK-TIU-TKP.txt', '51'),
    ('13c0b2db4b3552db6e1ce0c727a8a622b1d0c012', 'TIU', 'logika-analitis', 'sedang', 'draft', '8, 24, 22, 56, 18, __', '122', '124', '126', '128', '130', null, '2. SOAL LATIHAN TWK-TIU-TKP.txt', '58'),
    ('892f608a458b5f194c27ff891ec159e949d6651f', 'TIU', 'logika-analitis', 'sedang', 'published', 'D, E,E,F, F, G, __', 'H dan I', 'G dan G', 'G dan H', 'G dan I', 'H dan H', 'D', '2. SOAL LATIHAN TWK-TIU-TKP.txt', '59'),
    ('91803a612764aa46cf3bff573655c1195719f7ac', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Semua menu makanan restoran B diolah dari bahan organik. Semua menu dengan bahan organik diolah dengan cara tidak digoreng.', 'Sebagian menu makanan diolah tanpa menggunakan minyak (tidak digoreng).', 'Semua menu yang diolah dengan cara digoreng bukan menu resto ran B.', 'Semua menu restoran B diolah tanpa digoreng dengan minyak.', 'Sebagian menu restoran B dengan bahan organik diolah dengan cara digoreng.', 'Semua menu diolah dengan cara digoreng menggunakan bahan organik.', null, '2. SOAL LATIHAN TWK-TIU-TKP.txt', '60'),
    ('4f7c326a5fdd18665e26fee4363604ce6211ec5f', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Jika Tono lulus kurang dari satu atau sama denga n 4 tahun, maka ia akan diterima berkerja sebagai karyawan di perusahaan A. Jika Tono sudah bekerja di perusahaan A, maka ayahnya akan membelikan Tono sebuah sepeda motor. Tono tidak mendapat sepeda motor dari ayahnya.', 'Tono menyeleseikan studinya kurang dari 4 tahun.', 'Tono menyeleseikan studinya lebih dari 4 tahun.', 'Tono bekerja di perusahaan A.', 'Tono menyeleseikan studinya tepat 4 tahun.', 'Tono bekerja dengan sepeda motor. Teks logika Analitik Enam orang siswa yaitu Amir, Kiki, Shafira, Ali, Wahyu, Dan Rara ingin mengikuti latihan olahraga. Jadwal olahraga yang tersedia: basket dan karate hari Selasa, badminton dan renang hari Kamis, baseball dan tenis meja hari Jumat.  Setiap anak hanya bisa mengikuti paling banyak satu jenis olehraga dalam satu hari.  Amir dan Shafira diwajibkan orang tua mereka untuk mengikuti olahraga renang.  Rara dan Kiki telah bersepakat untuk memilih olahraga badminton.  Hanya Rara dan Wahyu yang tidak mengikuti olah raga basket.  Rara tidak memilih tenis meja.', null, '2. SOAL LATIHAN TWK-TIU-TKP.txt', '61'),
    ('fcaab93fcee04fd48f20c07c3f8302d4621a042f', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Olahraga apa yang bisa dilakukan oleh Rara dan Shafira secara bersamaan?', 'B. C. D. E.', 'Badminton', 'Renang', 'Baseball', 'Karate 63. Gambar selanjutnya adalah ...', null, '2. SOAL LATIHAN TWK-TIU-TKP.txt', '62'),
    ('beace33028446035ff6386d0e097df76fd32b509', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Kadangkala saya merasa lapar ketika jam kerja, maka yang saya lakukan adalah ...', 'Menyelesaikan pekerjaan terlebih dahulu kemudian makan', 'Meminta izin atasan untuk makan', 'Meminta teman menggantikan kerja sebentar', 'Ke pantry segera membuat makanan', 'Pergi ke warung terdekat untuk membeli makan', null, '2. SOAL LATIHAN TWK-TIU-TKP.txt', '66'),
    ('38831de032c8e1c048a4eb2c75e53ec587007278', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Ketika sedang diminta pimpinan untuk bekerja lembur, tiba -tiba ada telepon dari rumah memberi tahu bahwa anak sedang sakit, sikap kita ...', 'Segera kembali ke rumah', 'Pekerjaan kantor lebih penting', 'Meminta istri untuk lembur selesai', 'Melihat dulu kondisinya, apabila sakit parah segera kembali rumah', 'Sudah ada istri dan pembantu di rumah', null, '2. SOAL LATIHAN TWK-TIU-TKP.txt', '67'),
    ('150e70a37a5f7801dcc805b1ce11c3ff0d38e588', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Karena lembur kerja kemarin, siang ini saya merasa sangat mengantuk, kerjaan tidak ada yang selesai karena tidak fokus, sebaiknya saya ...', 'Segera tidur siang', 'Segera makan siang', 'Meminta izin atasan untuk istirahat sejenak', 'Meminta teman untuk memijat', 'Segera ke musholah untuk tidur', null, '2. SOAL LATIHAN TWK-TIU-TKP.txt', '68'),
    ('26538bada7a2a92f83b3f40408ec89acf0e0aa4b', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Saat ulang tahun pimpinan kantor, teman -teman seruangan berencana memberikan pesta kejutan, tapi kekurangan dana maka kami mengambil dana pembiayaan rapat, mengenai hal ini ...', 'Tidak apa-apa asalkan sedikit', 'Menolak rencana ini', 'Menghimbau agar patungan saja', 'Tidak ikut-ikutan', 'Memakai dana sponsor', null, '2. SOAL LATIHAN TWK-TIU-TKP.txt', '69'),
    ('91fb6d727198103bc941dd36a8431e292f518945', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Jika saya sedang mengerjakan sesuatu, kondisi yang dapat mendukung saya bekerja optimal adalah ...', 'Kondisi tenang dan santai', 'Saat tidak ada seorangpun dalam ruangan', 'Dengan ruangan nyaman dan dingin', 'Apapun kondisinya saya berusaha sekuat tenaga', 'Saya gunakan pikiran saya agarfokus pekerjaan bukan masalah tempat', null, '2. SOAL LATIHAN TWK-TIU-TKP.txt', '70'),
    ('37a0ab1d03301ddf0127c01a0d8dce4e5348c412', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Target kerja dan beban kerja yang tinggi menurut saya adalah ...', 'Suatu tantangan yang harus kita hadapi', 'Merupakan jalan kita untuk melangkah kedepan', 'Lebih baik saya menbgundurkan diri daripada saya stress', 'Merupakan jalan saya mencapai tingkat pimpinan tertinggi', 'Sebagai sarana melatih diri', null, '2. SOAL LATIHAN TWK-TIU-TKP.txt', '71'),
    ('b3a5cc3b48953117ca5f8617e7cf7b9a6ade8083', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Ditengah proyek besar dan membutuhkan tanggung jawab besar saya mengalami kegagalan besar yang sangat mengancam karir saya, sebaiknya saya ..', 'Meminta maaf atas kegagalan saya', 'Bertanggung jawab sepenuhnya atas apa yang saya lakukan', 'Tidak berputus asa, saya jadikan kegagalan ini sebagai penguat langkah kedepan', 'Bertanggung jawab dengan segera mengundurkan diri dari pekerjaan', 'Mencari-cari dalang dibalik kegagalan ini', null, '2. SOAL LATIHAN TWK-TIU-TKP.txt', '72'),
    ('7423d6e4c46621795a3343e81a52d79f9e5b0fd2', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Ada tawaran beasiswa melanjutkan pendidikan di luar negeri, tapi anda telat mengumpulkan syarat pendaftaran sehingga tidak dapat mengikuti tes masuk, mengenai hal ini ...', 'Saya tetap berusaha agar bisa mengikuti seleksi beasiswa', 'Tidak berputus asa, berusaha menyiapkan segala persyaratan untuk tahun depan', 'Meminta pimpinan agar masih diperbolehkan mengikuti tes masuk', 'Biasa saja karena masih ada tahun depan', 'Tidak terlalu memusingkan karena saya punya koneksi dalam agar bisa ikut beasiswa', null, '2. SOAL LATIHAN TWK-TIU-TKP.txt', '73'),
    ('457a0bd1f36b7e1c3aff17475cbb7cf0c070be1f', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Saat sedang rapat be rsama seluruh pegawai divisi tempat saya bekerja, saya biasanya memberikan masukan berupa pendapat tetapi beberapa teman saya juga memberikan pendapat, sikap saya akan hal ini ...', 'Tetap berpegang teguh pada ide saya', 'Mencoba mempengaruhi yang lain agar setuju terhadap pendapat saya', 'Saya cukup dekat dengan pimpinan rapat, saya yakin ide saya disetujui', 'Bersikap terbuka dan menerima semua pendapat yang ada', 'Mencoba selalu berfikir positif atas segala keputusan rapat', null, '2. SOAL LATIHAN TWK-TIU-TKP.txt', '74'),
    ('bd12a1c1b4fcf050619d91e8c453eec0806ddffe', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Jika ada waktu luang, selama akhir pekan saya biasanya ...', 'Gunakan untuk tidur siang', 'Saya ajak keluarga untuk makan di luar', 'Berlatih bermain musik', 'Saya gunakan untuk mempelajari hal-hal lain yang sifatnya positif', 'Saya gunakan untuk menyelesaikan pekerjaan kantor yang belum selesai', null, '2. SOAL LATIHAN TWK-TIU-TKP.txt', '75'),
    ('17e77fafc8ea8ccb2e8719f59aa75bf76e310716', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Pimpinan menginginkan agar berita -berita yang sedang hangat dibicarakan dibuat sebuah kumpulan berita agar memudahkan dibaca nantinya, maka sebaiknya ...', 'Saya buatkan kliping koran dengan jangka waktu tiap bulan', 'Saya kumpulkan berita-berita dari internet internet dan saya bookmark tiap alamatnya', 'Saya kumpulkan berita majalah dan koran yang berisi berita penting', 'Saya bersama teman-teman menyimpan tiap koran dan majalah ke rak-rak khusus', 'Saya meminta OB untuk mengkliping koran yang penting', null, '2. SOAL LATIHAN TWK-TIU-TKP.txt', '76'),
    ('9227396b329bb6d417be4330f029c78f91bd4220', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Anda memiliki beberapa rumah yang disewakan. Salah satu orang yang menyewa rumah anda melaporkan jika rumah anda bocor. Maka yang akan anda lakukan adalah ...', 'Segera membenahi kebocoran tersebut', 'Membebankan tanggung jawab kepada si penyewa', 'Memberikan penawaran rumah anda yang lain untuk ditempati', 'Meminta pada penyewa untuk sementara menambalnya sendiri', 'Meminta pada penyewa rumah untuk segera meninggalkan rumah tersebut bila sudah tidak nyaman', null, '2. SOAL LATIHAN TWK-TIU-TKP.txt', '77'),
    ('e1c820785e3f0e02a849356d46f139ad86b6f570', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Anda akan kedatangan rekan kerja anda dari luar kota. Dia berencana menginap di rumah anda. Maka yang akan anda lakukan adalah ...', 'Meminta kantor untuk memfasilitasi kedatangannya selama di rumah anda', 'Menolaknya secara halus', 'Menyiapkan segala yang diperlukan sesuai dengan kemampuan anda', 'Meminta rekan anda untuk membawa perlengkapannya sendiri', 'Membolehkannya menginap di rumah asalkan urusan anda dimudahkan', null, '2. SOAL LATIHAN TWK-TIU-TKP.txt', '78'),
    ('8fdfffc3cf7d1540ed187c5c5faef2579fdd16d5', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Seringkali terjadi kelalaian ketika kita memesan makanan, pelayan tidak langsung memberitahukan bila makanan yang kita pesan tersebut sudah habis. Menurut anda sebagai pelanggan yang perlu ditanggulangi dari hal tersebut adalah ...', 'Pelayan tersebut segera memberi tahu jika makanan yang anda pesan sudah habis', 'Memberikan anda alternatif makanan lain saat anda memesan makanan', 'Membrikan catatan dimenu jika makanan tersebut sudah habis', 'Dengan inisiatif pribadi pelayan tersebut langsung mengganti menu yang hampir sama', 'Memberitahu anda bila anda bertanya', null, '2. SOAL LATIHAN TWK-TIU-TKP.txt', '79'),
    ('d8acb07bcad969f8566770715a10c4f15110b396', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Anda berencana untuk mengambil sisa cuti tahunan. Namun, tiba -tiba rekan anda meminta anda agar membatalkan cutinya karena rekan anda ingin men jenguk keluarganya yang sakit di luar kota. Maka reaksi yang anda berikan pada kejadian tersebut adalah ...', 'Menunda cuti', 'Tetap cuti karena hak', 'Meminta maaf karena tidak dapat membantu', 'Mempertimbangkannya', 'Cuti bersamaan', null, '2. SOAL LATIHAN TWK-TIU-TKP.txt', '80'),
    ('7ae9aa35b8af360cea3e7e4f0d7a7e516ab302ea', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Tetangga anda sakit dan tidak bisa mengantar anaknya berangkat ke sekolah. Maka yang anda lakukan adalah...', 'Membelikan obat agar lekas sembuh', 'Menawarkan diri untuk mengantarkan anaknya ke sekolah', 'Membawa tetangga ke rumah sakit', 'Menyarankan agar anak tidak perlu ke sekolah', 'Menelpon wali kelas dan meminta agar si anak tidak ke sekolah', null, '2. SOAL LATIHAN TWK-TIU-TKP.txt', '81'),
    ('c5afba0c36e6db9ec81f388de7a1b4a168a69182', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Rekan kerja anda dimarahi oleh atasan karena ada dokumen yang hilang. Maka yang anda lakukan adalah ...', 'Membiarkannya untuk mengingat dimana dokumen tersebut', 'Menenangkannya karena dimarahai oleh atasan', 'Membantu mencari dokumen yang hilang', 'Ikut menyalahkannya', 'Pura-pura tidak tahu', null, '2. SOAL LATIHAN TWK-TIU-TKP.txt', '82'),
    ('30b7283b02af4030633ef0db4a4daed27744d547', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Sebagai pegawai baru yang akan anda lakukan ...', 'Bekerja sebaik mungkin', 'Mengerjakan tugas yang diberikan atasan', 'Berusaha secepat mungkin mempelajari tugas dan tanggung jawab serta mem bangun relasi dengan rekan kerja', 'Banyak bertanya pada rekan kerja tentang pekerjaan', 'Mengobservasi cara kerja rekan', null, '2. SOAL LATIHAN TWK-TIU-TKP.txt', '83'),
    ('3fe0168230a89f7a02b0435176391603b171d4fa', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Peraturan baru mengubah sistem 3 shift menjadi 2 shift, terjadi perubahan waktu kerja. Kebetulan anda bekerja sekaligus kuliah. Cara anda menyikapi peraturan tersebut dengan ...', 'Mengatur ulang jadwal kuliah agar tidak mengganggu jam kerja', 'Mengkomunikasikan kepada atasan tentang jadwal kerja dan kuliah agar tidak bentrok', 'Cuti kuliah sementara waktu sampai anda dapat membagi waktu dengan peker jaan', 'Mengundurkan diri dari pekerjaan', 'Mencari kampus lain yang dapat menyesuaikan jadwal kuliah dengan jam kerja', null, '2. SOAL LATIHAN TWK-TIU-TKP.txt', '84'),
    ('d6ffc88ffd0cc73a73539e7e76bf6f3865c39075', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Anda adalah pegawai pusat yang mendapatkan kanaikan jabatan dan ditempatkan di daerah terpencil. Maka anda akan ...', 'Melakukan negosiasi agar ditempatkan di kota besar', 'Menolak kenaikan pangkat tersebut dengan alasan belum mampu menjalankan amanat', 'Mengusulkan teman lain untuk diajukan', 'Menerima dan menjalankan tugas tersebut dengan penuh btanggung jawab', 'Meminta dimutasi ke divisi lain', null, '2. SOAL LATIHAN TWK-TIU-TKP.txt', '85'),
    ('ab2e36d286e5ae4b9f2f355d78110065bf05ad79', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Anda baru sadar dompet anda tertinggal padahal anda sudah berada di dalam angkutan umum, maka anda akan ...', 'Meminjam uang pada penumpang lain', 'Segera turun dan kembali ke rumah', 'Berkata jujur pada supir angkutan dan meminta maaf', 'Panik', 'Malu', null, '2. SOAL LATIHAN TWK-TIU-TKP.txt', '86'),
    ('e8aba8921b4abb64bae89bab17af7123c2893c6d', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Ketika di dalam lift, anda hanya berdua dengan pejabat, maka anda akan ...', 'Segera keluar lift', 'Salah tingkah', 'Menyapa dengan sopan', 'Bisa saja', 'Pura-pura sibuk bermain gadget', null, '2. SOAL LATIHAN TWK-TIU-TKP.txt', '87'),
    ('8c4cd07d63298232449179244e3596dd881faae8', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Anda sedang ada janji dengan teman -teman anda, tapi teman-teman anda datang terlambat, maka sikap anda ...', 'Sabar', 'Hal itu sudah baisa', 'Marah', 'Menegur keterlambatan mereka', 'Lain kali datang terlambat saja', null, '2. SOAL LATIHAN TWK-TIU-TKP.txt', '88'),
    ('665a29c441e9ba26bb2abb5d44b393d52f05d40a', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Suatu ketika rekan kerja anda banyak yang lembur, sementara anda sudah menyelesaikan pekerjaan, maka anda akan ...', 'Ikut lembur karena sungkan', 'Izin pulang dan menyerahkan pekerjaan yang sudah anda selesaikan', 'Ikut lembur dengan keadaaan terpaksa', 'Tetap pulang sambil menertawakan teman yang lembur', 'Pulang diam-diam', null, '2. SOAL LATIHAN TWK-TIU-TKP.txt', '89'),
    ('ec85ae6f1c9bb3c0879cc51b0fedce6ef622e8a2', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Anda adalah seorang Puteri Indonesia sekaligus, suatu ketika anda akan mengikuti karantina Miss Unive rse, sedangkan masih banyak sekali beban pekerjaan kantor yang harus anda selesaikan, maka anda akan ...', 'Keluar dari PNS', 'Meminta izin atasan agar bisa melimpahkan pekerjaan ke rekan yang lain', 'Segera menyelesaikan pekerjaan, kalau tidak terkejar, baru meminta izin atasan', 'Mengundurkan diri dari kontes Miss Universe', 'Marah pada keadaan', null, '2. SOAL LATIHAN TWK-TIU-TKP.txt', '90'),
    ('b6f41032ff1f636c860645ae9dee21c8c79e6c5b', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Sebagai seorang artis papan atas, anda sedang menyelesaikan sinetron stripping dan sedang kejar tanyang, padahal anda sangat lelah dan ingin istirahat beberapa hari, maka sikap anda ...', 'Memohon izin cuti beberapa hari', 'Tetap melanjutkan shooting karena harus profesional', 'Mengkonsumsi suplemen dan vitamin agar bisa tetap fit untuk menyelesaikan shooting', 'Pura-pura sakit', 'Bekerja asal-asalan', null, '2. SOAL LATIHAN TWK-TIU-TKP.txt', '91'),
    ('df363c39c6a3bd5d25066e75cec4e977c537939e', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Hari ini anda kehujanan ketika pulang kantor, maka anda akan ...', 'Menyalahkan ramalan cuaca', 'Biasa saja', 'Menyiapkan payung di dalam tas', 'Membawa baju lebih untuk hari-hari berikutnya', 'Berdoa agar tidak hujan', null, '2. SOAL LATIHAN TWK-TIU-TKP.txt', '92'),
    ('9933afdc915941f8f25e35bc9ec369ad4841bf49', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Suatu ketia anda ditugaskan di front office untuk melayani pelanggan, padahal sebelumnya anda tidak pernah bekerja di bagian tersebut, maka anda akan ...', 'Segera belajar', 'Asal bekerja', 'Bekerja sebisanya', 'Siap belajar dari apa yang nanti didapatkan dalam praktiknya', 'Takut', null, '2. SOAL LATIHAN TWK-TIU-TKP.txt', '93'),
    ('a6699f0b654ad7bb27017f34b19ac96675c33206', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Bagaimana cara anda bekerja ...', 'Mengikuti SOP yang ada', 'Mengikuti cara senior', 'Dengan cara sendiri', 'Mengikuti aturan yang ada', 'Mengikuti SOP dengan menambahkan sedikit motifasi', null, '2. SOAL LATIHAN TWK-TIU-TKP.txt', '94'),
    ('61c22f03fb43dc4a49c4af7a3620ba0dce64b181', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Ketika banyak anggota tim kerja anda yang berbeda suku dengan anda, maka anda akan ...', 'Bersikap toleran dan menghormati mereka', 'Menjaga jarak dengan mereka', 'Waspda dalam bersikap', 'khawatir jika ucapan anda dapat menyinggung mereka', 'meminta atsan untuk memindahkan anda ke tim kerja yang lain saja', null, '2. SOAL LATIHAN TWK-TIU-TKP.txt', '95'),
    ('a59afe8cfc4ca010761c52a73609ec1b467db0fa', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'ketika banyak anggota tim kerja anda yang berbeda agama dengan anda, maka anda akan ...', 'bersikap toleran dan menghormati mereka', 'Menjaga jarak dengan mereka', 'Waspda dalam bersikap', 'Khawatir jika ucapan anda dapat menyinggung mereka', 'Meminta atsan untuk memindahkan anda ke tim kerja yang lain saja', null, '2. SOAL LATIHAN TWK-TIU-TKP.txt', '96'),
    ('d813c7340d2c95ade4d3292d246df767efe23c27', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Salah seorang rekan kerja dalam tim kerja anda merupakan seorang pegawai baru, mak a anda ...', 'Senang karena dia bisa dijadikan pesuruh', 'Senang membentunya dalam mempelajari lingkungan kerja', 'Cuek saja walau ia meminta bantuan pada saya', 'Berusaha bersikap dengan penuh wibawa di depannya', 'Meminta atasan untuk menggantinya dengan alasan ia belum siap dilibatkan dalam kerja tim', null, '2. SOAL LATIHAN TWK-TIU-TKP.txt', '97'),
    ('c993dacf67a0ae696a0e8d3ec115576aad59dc44', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Di kantor saya akan diadakan acara buka puasa bersama, maka saya akan ...', 'Mengikuti acara tersebut karena merasa tidak enak jika tidak ikut', 'Pulang sebelum acara tersebut selesai', 'Izin tidak mengikuti acara tersebut karena anda sudah lelah', 'Ikut acara tersebut karena banyak rekan saya yang juga mengikutinya', 'Mengajak rekan-rekan sekantor untuk berpartisipasi dalam acara tersebut', null, '2. SOAL LATIHAN TWK-TIU-TKP.txt', '98'),
    ('ccd2a95455478119fad175f845409e61b5e48ca4', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Di kantor saya akan diadakan acara sarapan bersama, maka saya akan ...', 'Mengikuti acara tersebut karena merasa tidak enak jika tidak ikut', 'Pulang sebelum acara tersebut selesai', 'Izin tidak mengikuti acara tersebut karena anda sudah sarapan', 'Ikut acara tersebut karena banyak rekan saya yang juga mengikutinya', 'Mengajak rekan-rekan sekantor untuk berpartisipasi dalam acara tersebut', null, '2. SOAL LATIHAN TWK-TIU-TKP.txt', '99'),
    ('c69cd0d35db0aecce236793870db80614cecc97b', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Jika anak anda marah karena tidak belikan sebuah mainan yang dia inginkan, maka anda akan ...', 'Memberinya pengertian agar membeli barang yang lebih banyak manfaatnya saja', 'Menyuruhnya untuk berhenti marah', 'Memarahinya agar berhenti merengek', 'Mendiamkannya hingga ia tenang', 'Meninggalkannya di toko mainan tersebut', null, '2. SOAL LATIHAN TWK-TIU-TKP.txt', '100'),
    ('9848ef9bc5e9b17ac714b3dfe6082f725440eff3', 'TWK', 'wawasan-kebangsaan', 'sedang', 'draft', 'Konsepsi Pancasila tentang hubungan antara manusia dan masyarakatnya adalah terciptanya keselarasan, keserasian, dan keseimbangan yang berarti...', 'Mengutamakan kepentingan umum dan mendahulukan kepentingan pribadi dan golongan.', 'Melepaskan diri demi kepentingan umum dan meletakkan kepentingan pribadi sebagai yang pertama.', 'Memperlakukan dengan sama antara kepentingan umum dan pribadi', 'Meletakkan kepentingan umum di atas kepentingan pribadi dan golongan', 'Melepaskan kepentingan um um dan mengutamakan kepentingan pribadi dan golongan', null, '3. SOAL LATIHAN TWK-TIU-TKP.txt', '1'),
    ('e9f824e8beff5b727e76325741eb3731c6a933f2', 'TWK', 'wawasan-kebangsaan', 'sedang', 'draft', 'Setiap ilmuwan harus memiliki kebebasan untuk mengembangkan iptek, tetapi dengan menghormati dan menghargai kebebasan orang lain serta harus terbuka terhadap masukan-masukan dari luar. Hal tersebut mer upakan perwujudan dari pembangunan iptek yang berdasar pada pancasila sila ...', 'Pertama', 'Kedua', 'Ketiga', 'Keempat', 'kelima', null, '3. SOAL LATIHAN TWK-TIU-TKP.txt', '2'),
