    ('1779e7f3ae0dcfa5309a59ccd6480d04ac6a32f3', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Jika {x2 – 4 = 0} dan {y = 2}, manakah pernyataan berikut yang benar?', 'x > y', 'x < y', 'x = y', 'hubungan x dan y tak dapat ditentukan', 'x ≠ y', null, '6. SOAL LATIHAN TWK-TIU-TKP.txt', '50'),
    ('971e8ad73420106507a6610fc9d5745d2f1ad6e5', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Jika p > 0, q < 0, {x = p2 + q2}, dan {y = (p+q)2}, manakah pernyataan berikut yang benar?', 'x > y', 'x < y', 'x = y', 'hubungan x dan y tak dapat ditentukan', 'x ≠ y', null, '6. SOAL LATIHAN TWK-TIU-TKP.txt', '51'),
    ('f7e7a5a8a481264ac2397ee7af40625fa162bb0b', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Pernyataan yang benar adalah ...', 'Bandi lebih tinggi daripada Ridwan', 'Ridwan lebih tinggi daripada Yudi', 'Joko lebih tinggi daripada Bandi', 'Ridwan lebih tinggi daripada Amir', 'Joko lebih lebih tinggi daripada Ridwan', null, '6. SOAL LATIHAN TWK-TIU-TKP.txt', '62'),
    ('951aaa1eabbec3301f8c2157c05e93bdeaa24ab2', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Jika Bandi lebih tinggi daripada Ridwan, maka ...', 'Amir lebih tinggi daripada Ridwan', 'Bandi lebih tinggi daripada Joko', 'Yudi lebih tinggi daripada Ridwan', 'Joko lebih tinggi daripada Iwan', 'Iwan lebih tinggi daripada Bandi', null, '6. SOAL LATIHAN TWK-TIU-TKP.txt', '63'),
    ('c0ffc6a0e77881d23741c52453f7e1952021a588', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Diam-diam ubi berisi, diam-diam penggali berkarat.', 'Diamnya orang pandai itu emas, diamnya orang bodoh itu lumpr', 'Diamnya orang pandai itu berpikir, diamnya orang yang bodoh sia-sia', 'Melakukan perbuatan baik tanpa harus diketahui oleh orang lain', 'Memamerkan perbuatan baik yang jarang dilakukan', 'Orang yang selalu menjadi panutan bagi orang lain', null, '6. SOAL LATIHAN TWK-TIU-TKP.txt', '64'),
    ('d7d2bc51b142e561ee3e5c8693d20ba35d59cbc7', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Ketika ada jangan dimakan, telah habis maka dimakan. Makna peribahasa di atas adalah ...', 'Harta benda kita harus dibagikan ke orang lain yang lebih membutuhkan', 'Harta benda tidak dibawa mati', 'Jangan serakah akan akan kekayaan yang dimiliki', 'Hemat dan menabung adalah cara untuk kaya', 'Hiduplah hemat dan suka menabung. Selama tidak terdesak, janganlah tabungan itu diusik-usik', null, '6. SOAL LATIHAN TWK-TIU-TKP.txt', '65'),
    ('66639729bb8b5bcc1658858d6658523b0eb32eca', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Atas segala perkataan dan perintah atasan saya ...', 'Mempercayainya', 'Segera melaksanakan', 'Menganggapnya hanya bualan', 'Menyanggupi', 'Menimbang terlebih dahulu', null, '6. SOAL LATIHAN TWK-TIU-TKP.txt', '66'),
    ('98c51599589a7a8222550e268b18670383039343', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Rekanan memberikan sejumlah uang atas balas jasa, sikap saya ...', 'Menolak dan memberi pengertian', 'Menolak dan melaporkannya ke KPK', 'Menolak karena jumlahnya sedikit', 'Menerima karena rekanan masih saudara', 'Menerima asal pimpinan ikut menerima', null, '6. SOAL LATIHAN TWK-TIU-TKP.txt', '67'),
    ('6b52902fe35317ca7a67d9d11508a48ac8388e1e', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Biasnya teman kerja menrima konsumsi apabila sedang melakukan kegiatan audit, mengenai hal ini ...', 'Biasa saja', 'Bukan merupakn korupsi', 'Asal tidak mewah tidak apa-apa', 'Sebaiknya beli sendiri', 'Memberikan penjelasan kepada auditee mengenai kode etik', null, '6. SOAL LATIHAN TWK-TIU-TKP.txt', '68'),
    ('2eaf525d767986a9e91c2d986d81c8359d342337', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Banyak senior di kantor yang memakai sendal saat kerja, saya sebagai junior yang baru masuk ...', 'Tidak ikut', 'Memberi contoh dengan mamakai sepatu', 'Tergantung perintah pimpinan', 'Ikut kebiasaan yang sudah ada', 'Menegur senior', null, '6. SOAL LATIHAN TWK-TIU-TKP.txt', '69'),
    ('45cdea81b0e920f12ca46f1344982cf34815df7d', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Hal pertama yang anda lakukan ketika datang ke kantor adalah ...', 'Menyalakan komputer kemudia membuka facebook', 'Sarapan terlebih dahulu di kantin', 'Menata ruang kerja', 'Menyelesaikan pekerjaan yang tertunda kemarin', 'Menyusun rencana kerja dan target jangka pendek', null, '6. SOAL LATIHAN TWK-TIU-TKP.txt', '70'),
    ('1f92dec0791618553eecfb9746c1bd4bd97d9591', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Salah satu rekan kerja saya ada yang terindikasi memakai obat -obatan terlarang, saya sebagai teman kerja harusnya ...', 'Memberinya nasihat dan semangat agar bisa lepas dari jeratan obat terlarang', 'Memberikan pengertian bahaya narkoba', 'Mengajaknya untuk mengikuti rehabilitasi dari kecanduan narkoba', 'Melaporkannya ke pimpinan', 'Acuh saja karena bukan merupakan masalah saya', null, '6. SOAL LATIHAN TWK-TIU-TKP.txt', '71'),
    ('8d4a23b194dba1d41de25a8c94809f776c5f47fb', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Saya ditawari pimpinan untuk promosi jabatan menjadi kepala seksi, tetapi saya harus mutasi kerja keluar pulau padahal istri saya baru saja melahirkan, sikap yang saya ambil ...', 'Menolak tawaran tersebut', 'Menerima jika diberi uang pindah dengan jumlah yang besar', 'Menerima tawaran tersebut asalkan keluarga juga ikut pindah', 'Menerima tawaran tersebut dengan konsekuensi keluarga saya tinggalkan sementara', 'Meminta agar promosi jabatan di kota tempat tinggal saja', null, '6. SOAL LATIHAN TWK-TIU-TKP.txt', '72'),
    ('53b89221fffdf7b41674b9f4d5f0275516bd7a5a', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Bekerja menurut saya selain sebagai cara mencari kesuksesan adalah sabagai ibadah, untuk itu saya ...', 'Bekerja keras setiap waktu', 'Berusaha sekuat tenaga demi keluarga', 'Berusaha sekuat tenaga dan memberikan terbaik', 'Melakukan apa saja demi kesuksesan', 'Bekerja secara profesional dan sungguh-sungguh', null, '6. SOAL LATIHAN TWK-TIU-TKP.txt', '73'),
    ('5278f4ebec19353b7aff9d5bf28c51bebe078efb', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Setiap pekerjaan berat dan dengan tenggat waktu yang sempit menurut saya...', 'Merupakan pekerjaan yang tidak cocok dengan karakter saya', 'Saya tidak akan mampu mengerjakannya', 'Merupakan sebuah tantangan sendiri buat saya', 'Sebagai sarana berfikir kreatif dan inovatif dalam menyelesaikan setiap tantangan', 'Saya gunakan sebagai bahan acuan untuk melatih rasa tanggung jawab saya', null, '6. SOAL LATIHAN TWK-TIU-TKP.txt', '74'),
    ('62c86fa5beb322839d5b597fb24de9abb335d7c8', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Pimpinan memberikan sebu ah pekerjaan kepada saya, biasanya pekerjaan ini diselesaikan dalam waktu satu bulan, tetapi saya memiliki cara agar pekerjaan ini dapat selesai dalam 2 minggu dengan sedikit menerobos aturan normal yang ada, maka sebaiknya ...', 'Saya menggunakan cara yang biasa digunakan sehingga tidak timbul permasalahan', 'Saya gunakan cara yang baru dengan syarat tidak melanggar peraturan perundangan yang ada', 'Saya gunakan cara yang lain meskipun waktunya juga sama sebulan', 'Saya meminta petunjuk atasan', 'Saya gunakan cara yang baru yang penting pekerjaan dapat selesai lebih cepat dan rapi', null, '6. SOAL LATIHAN TWK-TIU-TKP.txt', '75'),
    ('6300559e0493f868f0edd23d60e1b9d8191abf75', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Ide saya kadang kala tidak didengar oleh pimpinan, mengenai hal ini sebaiknya saya ...', 'Berusaha sekuat tenaga agar pendapat saya didengarkan pimpinan', 'Bersikap biasa saja karena kadangkala ada ide lain yang lebih baik', 'Intropeksi diri terlebih dahulu, mungkin dalam menyampaikan ide saya ada kesalahan', 'Saya gun akan sebagai bahan pembenahan diri', 'Mungkin ide yang saya sampaikan kurang berguna buat organisasi, oleh karena itu dikemudian hari sebisa mungkin saya beri ide yang lebih baik', null, '6. SOAL LATIHAN TWK-TIU-TKP.txt', '76'),
    ('d7ca7e6d70019c84b36423aa87a29a0fdc68dda3', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Anda ingin menambah menu makanan atau minuman apa cafe anda. Agar mendapatkan respon positif dari pelanggan yang anda lakukan adalah ...', 'Membuat menu dengan nama yang unik', 'Menerima masukan dari pelanggan', 'Mancari chef handal', 'Menawarkan harga murah pada menu baru', 'Memberikan sampel makanan pada pengunjung', null, '6. SOAL LATIHAN TWK-TIU-TKP.txt', '77'),
    ('045bc10103666ef484f7463143c3b8ba42f68798', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Pendingin di lobi kantor anda mengalami kebocoran. Maka yang akan anda lakukan adalah ...', 'Memindahkan benda-benda agar tidak basah', 'Meminta cleaning service untuk membersihkan', 'Memindahkan lobi ke area yang lebih nyaman', 'Segera memanggil teknisi', 'Memindahkan lobi agar teknisi dapat bekerja maksimal', null, '6. SOAL LATIHAN TWK-TIU-TKP.txt', '78'),
    ('d30cfb7cffdafceac84da37bc714b82585b07942', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Hujan yang turun membuatb lantai kantor menjadi licin dan kotor. Maka agar pelanggan merasa nyaman yang perlu anda lakukan adalah ...', 'Menjaga kebersiha lantai agar tetep kering', 'Membuat jalur darurat agar pelanggan tetap nyaman', 'Menyediakan tempat penitipan alas kaki', 'Memasang kardus di sepanjang jalan agar lantai tetap kering', 'Melarang setiap karyawan atau pengunjung masuk kantor dalam keadaan basah', null, '6. SOAL LATIHAN TWK-TIU-TKP.txt', '79'),
    ('ee04d3b6b3a0fbb20fbbc9c2ddf92211686dd46b', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Anda sedang menikmati musik lewat earphone anda. Tiba -tiba ada orang yang ingin menanyakan sesuatu pada anda. Maka yang anda lakukan adalah ...', 'Mengecilkan volume earphone dan menyimak pertanyaan', 'Jika memakai earphone saya tidak pernah memperhatikan sekeliling saya', 'Segera melepas earphone dan mendengarkan pertanyaan orang tersebut', 'Menjawab pertanyaan sambil memakai earphone', 'Membiarkan orang tersebut bertanya pada orang lain', null, '6. SOAL LATIHAN TWK-TIU-TKP.txt', '80'),
    ('e8da97c4a7183fc12110813e39e621caca498881', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Anda memiliki sahabat diluar kota yang akan menikah. Pada saat yan g bersamaan anda memiliki banyak pengeluaran. Maka yang anda lakukan adalah ...', 'Memberikan ucapan dan kado lewat jasa pengiriman', 'Mengupayakan untuk tetap datang', 'Akan mengunjunginya lain waktu', 'Meminjam uang agar dapat menghadiri acara tersebut', 'Memberi selamat lewat pesan singkat dan media sosial miliknya.', null, '6. SOAL LATIHAN TWK-TIU-TKP.txt', '81'),
    ('825c7bcca7889ad58cad20d23d530b2df827df0d', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Teman lama anda ingin melakukan peneletian di tempat kerja anda untuk tugas akhirnya. Maka yang anda dapat lakukan untuk teman anda adalah ...', 'Menyarankan agar mengambil tempat penelitian di tempat lain', 'Mencoba memberikan proposal penelitian pada atasan anda', 'Membantunya menyebarkan angket', 'Membantu memanipulasi angket bila tidak mendapatkan izin dari perusahaan', 'Mengisiangket tanpa sepengetahuan teman karena tidak ingin mengurus izin penelitian', null, '6. SOAL LATIHAN TWK-TIU-TKP.txt', '82'),
    ('e6dd21de81db0715b0fc419e66094a8132160d88', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Anda adalah orang yang kurang menyukai keramaian. Ketika anda diundang di acara pesta dan bertemu teman-teman anda maka ...', 'Berbincang seperlunya', 'Memilih untuk mencicipi hidangan', 'Berusaha agar tidak terlihat teman-teman yang lain', 'Berusaha membaur dengan teman-teman', 'Mengajak pasangan agar dapat menghindari teman', null, '6. SOAL LATIHAN TWK-TIU-TKP.txt', '83'),
    ('56128365ad86bec268d100a5f928c33c3ef98c49', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Anda baru saja menikah, kemudian anda akan sering ditigaskan ke luar kota dan ini masih berlanjut hingga akhir tahun. Maka cara anda menanggapi keputusan ini dengan cara ...', 'Mengajak pasangan dengan baiaya pribadi', 'Melobi atasan untuk melobi orang lain', 'Menjalankan tugas dan memberi pengertian pada pasangan', 'Mengundurkan diri', 'Melobi atasan agar diberi tugas lain', null, '6. SOAL LATIHAN TWK-TIU-TKP.txt', '84'),
    ('e7aabff07bfa0251c17050cbf9ca894e873c8741', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Anda baru saja mendapat rekan kerja. Maka anda dan rekan kerja anda akan ...', 'Bersaing untuk mendapatkan simpati atasan', 'Mengerjakan tugas masing-masing', 'Berusaha saling menjatuhkan demi membangun simpati', 'Mengenal rekan kerja dengan sering pergi bersama setelah pulang', 'Berusaha saling memahami dan bahu-membahu dengan maksimal', null, '6. SOAL LATIHAN TWK-TIU-TKP.txt', '85'),
    ('2284113ec903f85ac66e175915c1827cf86075ea', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Anda mendapatkan hadiah undian uang tunai jutaan rupiah, maka anda akan ...', 'Menabung', 'Membelanjakan seperlunya, kemudian ditabung', 'Segera membelanjakanya hingga habis', 'Membantu sesama', 'Membayar hutang', null, '6. SOAL LATIHAN TWK-TIU-TKP.txt', '86'),
    ('f7a7c33fecb432ec07fb8b786cae37d1d275f8f7', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Anda sedang digosipkan oleh rekan kerja anda yang lain, sikap anda ...', 'Bangga, karena merasa terkenal', 'Mengklarifikasi gosip yang beredar dengan baik-baik', 'Marah', 'Biasa saja', 'Menggosip balik', null, '6. SOAL LATIHAN TWK-TIU-TKP.txt', '87'),
    ('63a9b6b50fa1334df135562658f464d5d57c8dc0', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Saat menghadapi rekan kerja yang bermals-malasan, anda akan ...', 'Bersikap tegas', 'Mencoba memahami permasalahannya', 'Marah', 'Membiarbkan saja', 'Menganggapnya maklum, mungkin dia lelah', null, '6. SOAL LATIHAN TWK-TIU-TKP.txt', '88'),
    ('0f686f1d559fa4c11821efddcaf9b8796fb30d13', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Bagaimana sikap anda dalam bekerja', 'Bekerkja dengan santai sambil sesekali membuka sosial media', 'Bekerja dengan giat ketika diawasi', 'Bekerja sambil sesekali mengakses situs online shop', 'Berpura-pura bekerbja dengan tekun', 'Bekerja dengan giat baik diawasi maupun tidak', null, '6. SOAL LATIHAN TWK-TIU-TKP.txt', '89'),
    ('5011fd4f13405ab3aedfc995111787221cb87d31', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Sebagai ketua tim, anda mendapati anggota tim anda menjadi penghambat terselesaikannya pekerjaan, maka anda akan ...', 'Menegurnya didepan umum', 'Menegurnya dengan keras', 'Menanyakan permasalahan pekerjaannya', 'Membiarkannya', 'Mencoba mengetahui permasalahannya dan mencoba membantu menyelesaikannya', null, '6. SOAL LATIHAN TWK-TIU-TKP.txt', '90'),
    ('7014ba5dff2a9a66e7d066bbebc744adbf809f2e', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Menurut rekan kerja anda, anda adalah seorang yang ...', 'Rajin', 'Amanah', 'Supel', 'Tegas', 'Disiplin', null, '6. SOAL LATIHAN TWK-TIU-TKP.txt', '91'),
    ('fcb15737971ccf22ba52d2c56fd3cee01221a057', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Ketika tidak ada yang menyetujui usulan anda, maka anda akan ...', 'Sedih', 'Putus asa', 'Marah', 'Tidak mau mengajukan usul lagi', 'Berusaha memahami kondisi', null, '6. SOAL LATIHAN TWK-TIU-TKP.txt', '92'),
