    ('fdfdba3e0116722df4b19ff4e9702ac6cba118a0', 'TIU', 'logika-analitis', 'sedang', 'draft', 'jika (x = n.1.1), (y = n + 1 + 1) dan n adalah bilangan positif, manakah pernyataan berikut yang benar?', 'x > y', 'x < y', 'x = y', 'hubungan xx dan y tidak dapat ditentukan', 'x ≠ y', null, '7. SOAL LATIHAN TWK-TIU-TKP.txt', '51'),
    ('f843abcfa1bc137c856c6090d7fa697980dc7835', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Sebuah truk berangkat dari kota A pada pukul 11.53 dan tiba di kota B yang berjarak 240 km dari kota A pada pukul 16.11 hari yang sama. Berapakah kecepatan rata -rata truk tersebut dalam menempuh perjalanan dari A ke B?', '1.494/240 km/jam', '50 km/jam', '16/1.200 km/jam', '240/288 km/jam', '65 km/jam', null, '7. SOAL LATIHAN TWK-TIU-TKP.txt', '54'),
    ('adaeb29025a31beed9a579655ca3626b10b30f93', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Semua pekerja harus mengenakan topi pengaman. Sementara pekerja mengenakan sarung tangan.', 'Sementara pekerja tidak mengenakan topi pengaman.', 'Semua pekerja tidak mengenakan sarung tangan.', 'Sementara pekerja mengenakan topi pengaman dan sarung tangan.', 'Sementara pekerja tida k mengenakan topi pengaman dan mengenakan sarung tangan.', 'Sementara pekerja tidak mengenakan topi pengaman dan tidak mengenakan sarung tangan.', null, '7. SOAL LATIHAN TWK-TIU-TKP.txt', '61'),
    ('e7b8aa42e41a13c071e8b2487737c37afb204a89', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Semua anggota asosiasi profesi harus hadir dalam rapat. Sementara dokter adalah anggota asosiasi.', 'Semua yang hadir dalam rapat adalah dokter', 'Semua anggota rapat bukan anggota asosiasi profesi', 'Sementara peserta rapat adalah dokter', 'Semua dokter hadir dalam rapat', 'Semua yang hadir bukan dokter', null, '7. SOAL LATIHAN TWK-TIU-TKP.txt', '62'),
    ('50149af8d769fc82d34434b03fd825b370b58c7f', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Semua seniman kreatif. Sementara ilmuan tidak kreatif.', 'Sementara ilmuan bukan seniman', 'Tidak ada seniman yang ilmuan', 'Sementara individu yang kreatif bukan seniman', 'Sementara ilmuan kreatif', 'Sementara ilmuan kreatif', null, '7. SOAL LATIHAN TWK-TIU-TKP.txt', '63'),
    ('dc2b5b750258e775c1bc2193ad73d657b09fb8b0', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Orang mengantuk disorongkan bantal. Makna peribahasa di atas adalah ...', 'Mendapatkan bantuan tak disangka - sangka', 'Mendapatkan keuntungan besar', 'Mendapatkan musibah yang besar', 'Mendapatkan sesuatu yang sudah direncanakan', 'Mendapatkan sesuatu yang sangat idam-idamkan', null, '7. SOAL LATIHAN TWK-TIU-TKP.txt', '64'),
    ('110f3bb122a558418946d12cf2ed079f962cb4d0', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Tertumbuk biduk dikelokkan, tertumbuk kata dipikiri. Makna peribahasa di atas adalah ...', 'Menemukan masalah dalam pekerjaan', 'Bila mengerjakan sesuatu pekerjaan, harus beraturan', 'Mengerjakan suatu pekerjaan yang tidak dipikirkan', 'Menegerjakan sesuatu pekerjaan yang diperintahkan orang lain', 'Masalah datang setelah pekerjaan telah dilakukan', null, '7. SOAL LATIHAN TWK-TIU-TKP.txt', '65'),
    ('6cae720ea9a8661c370e8f4ee0285b3523577eda', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Menurut saya, saya adalah orang yang ...', 'Pekerja keras', 'Berambisi', 'Suka tantangan', 'Sabar', 'Bertanggung jawab', null, '7. SOAL LATIHAN TWK-TIU-TKP.txt', '66'),
    ('581c08a696e2f5fb6c9068af48ab5f0d84a452d4', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Dalam suatu kompetisi saya ...', 'Yakin akan mengalahkan lawan -lawan saya', 'Hanya ikut jika ada peluang untuk menang', 'Berusaha mengalahkan lawan -lawan saya dengan mencari kelemahan mereka', 'Takut akan kekalahan', 'Berusaha memberikan yang terbaik dari diri saya apapun hasilnya nanti', null, '7. SOAL LATIHAN TWK-TIU-TKP.txt', '67'),
    ('7586c6573ebbb45064367be910900e1bf19ada6c', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Perusahaan kami membentuk tim sepakbola untuk mengikuti kejuaraan antar perusahaan. Yang harus kami lakukan untuk dapat memenangi kejuaraan adalah ...', 'Berlatih dengan rutin', 'Mengadakahn petandingan uji coba untuk mengasah kemampuan tim kami', 'Berusaha mencari kelemahan tim kami', 'Mendatangkan pelatih yang bagus', 'Mencari pemain dari luar perusahaan untuk dimasukkan tim', null, '7. SOAL LATIHAN TWK-TIU-TKP.txt', '68'),
    ('c0b462c70aece401b71a01922d305b75f50f409a', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Dalam suatu rapat perusahaan, pendapat saya ditolak oleh peserta rapat. Saya akan ...', 'Berlapang dada menerima penolakan itu', 'Tidak terima dan langsung meninggalkan tampat rapat', 'Berusaha keras meyakinkan peserta rapat untuk menerima pendapat saya', 'Mengahragai perbedaan pendapat', 'Dengan berata hati menrima penolakan, dan mengikuti rapat hingga selesai', null, '7. SOAL LATIHAN TWK-TIU-TKP.txt', '69'),
    ('c1c38428d6d909737a618d93a28042204b355ec1', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Seorang teman mengajak saya memancing hari minggu. Padahal saya harus menyelesaikan tugas kantor yang dibutuhkan hari se nin. Terhadap ajakan itu saya akan ...', 'Menolak', 'Menolak, tetapi mengusulkan hari lain untuk memancing', 'Dengan berat hati menerimanya', 'Menerima dan meninggalkan pekerjaan', 'Menerima, namun hanya untuk beberapa waktu dan kemudian kembali untuk mneyelesaikan pekerjaan', null, '7. SOAL LATIHAN TWK-TIU-TKP.txt', '70'),
    ('c26a705e7a999feb210a21c7a2420d9dff53bf9b', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Tanpa sengaja saya bertemu teman lama saya yang lebih sukses dari saya. Saya akan ...', 'Menyapa dengan ramah', 'Diam saja sampai dia menyapa saya', 'Pura-pura tidak tahu', 'Berusaha menghindar', 'Merasa malu, menyapa sebentar dan kemudian bergegas pergi', null, '7. SOAL LATIHAN TWK-TIU-TKP.txt', '71'),
    ('de01a2e588af9793eb6631664b199a38fa8d238d', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Menurut saya kegagalan lebih disebabkan karena ...', 'Tidak berani menempuh resiko', 'Tidak mandiri', 'Tidak mempunyai tujuan', 'Tidak mempunyai kemampuan', 'Cepat puas', null, '7. SOAL LATIHAN TWK-TIU-TKP.txt', '72'),
    ('93cbefe5475a9e12fdc18a785ff25a6e4765eb67', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Ketika saya membutuhkan bantuan, teman saya menolak untuk memberikan bantuan. Saya akan ...', 'Menerima dengan lapang dada keputusannya', 'Memaksa untuk membantu saya', 'Sakit hati dan tidak akan membantunya jika dia membutuhkan pertolongan saya', 'Merasa sedih', 'Tidak mau berteman lagi dengannya', null, '7. SOAL LATIHAN TWK-TIU-TKP.txt', '73'),
    ('916a2de4d720ca534e328031e1ea99cb093d8fe6', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Beberapa bulan ini pembayaran gaju di perusahaan saya mengalami keterlambatan. Saya akan ...', 'Meminta penjelasan dari atasan', 'Mengajak teman -teman untuk menuntut pembayaran gaji tepat waktu', 'Tetap bekerja seperti biasa', 'Bekerja dengan setengah hati', 'Tidak terima dan keluar dari perusahaan', null, '7. SOAL LATIHAN TWK-TIU-TKP.txt', '74'),
    ('29fb23b8033ad5e23489d1e1a09f98148ebe29c8', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Ide-ide yang saya kemukakan biasan ya dianggap sebagai sesuatu yang ...', 'Biasa', 'Besar', 'Ketinggalan jaman', 'Baru dan menarik', 'Sesuai jamannya', null, '7. SOAL LATIHAN TWK-TIU-TKP.txt', '75'),
    ('99eb2f8c1126f0b9edab422815ea560cfa6e7020', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Dalam memilih rekan kerja, saya akan mengutamakan yang ...', 'Pekerja keras', 'Cerdas', 'Mudah menyesuaikan diri', 'Ulet', 'Berpengalaman', null, '7. SOAL LATIHAN TWK-TIU-TKP.txt', '76'),
    ('bf9f89de1818abeda32e6786a10ab61007de9286', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Saat makan siang saya mendapatkan makanan yang tidak sesuai dengan pesanan saya. Saya akan ...', 'Marah-marah dan meninggalkan tempat tersebut', 'Meminta ganti sesuai pesanan', 'Tetap memakannya dan membayar seperti biasa', 'Tetap memakannya dan meminta potongan harga', 'Menerima makanan tersebut, dan memesan lagi seperti keinginan', null, '7. SOAL LATIHAN TWK-TIU-TKP.txt', '77'),
    ('c87ac385e84bcc2939ddf5a8545ecc099279cf23', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Laporan kerja yang dikerjakan oleh tim kerja saya ditolak oleh atasan. Saya ...', 'Memperbaiki laporan dan mengajukannya kembali', 'Menerima penolakan dan berusaha memperbaiki', 'Menerima penolakan dan tidak berusaha memperbaiki', 'Menyalahkan teman yang mengerjakan bersama saya', 'Mencari-cari alasan seperti kurangnya waktu pengerjaan', null, '7. SOAL LATIHAN TWK-TIU-TKP.txt', '78'),
    ('002af9f616f8f7abc8efe501d381db4efd994637', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Saya datang ke kantor paling pagi dibandingkan pegawai lain. Yang saya lakukan ...', 'Menyelesaikan pekerjaan kemarin yang belum selesai', 'Membaca koran pagi di ruangan', 'Mempersiapkan semua yang diperlukan untuk pekerjaan hari ini', 'Membuat minuman dan kemudian mengobrol dengan teman kerja yang sudah datang', 'Santai dulu di luar gedung kantor', null, '7. SOAL LATIHAN TWK-TIU-TKP.txt', '79'),
    ('5238241f9ea65354e7dab13513454f3cebd12cd7', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Perusahaan memberikan beasiswa belajar di luar kota kepada say a. Padahal istri saya baru saja melahirkan. Saya akan ...', 'Menolak beasiswa tersebut', 'Mengambil beasiswa tersebut dan meninggalkan keluarga', 'Mengambil beasiswa dan mengajak serta keluarga, dengan konsekuensi menggunakan biaya pribadi', 'Mengambil beasiswa dan mengajukan permintaan agar keluarga bisa ikut serta dengan biaya perusahaan', 'Meminta penundaan beasiswa untuk tahun depan', null, '7. SOAL LATIHAN TWK-TIU-TKP.txt', '80'),
    ('40167ace0d6d29083857a18061145ce08aae3256', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Seorang teman menilai saya dengan sangat jelek. Saya akan ...', 'Sedih', 'Introspeksi diri', 'Berusaha mencari kejelekan teman tersebut', 'Tidak terima dan meminta penjelasan darinya', 'Biasa saja', null, '7. SOAL LATIHAN TWK-TIU-TKP.txt', '81'),
    ('e25c4961048adcb452acf3df8b29156fded22b41', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Akibat kemacetan jalan saya datang terlambat ke kantor dan dimarahi atasan saya. Saya ...', 'Merasa sebal karena atasan tidak mau mengerti keadaan kita', 'Menerima dan berjanji akan berusaha untuk berangkat lebih pagi lagi keesokan harinya', 'Memberi alasan telah terjadi kemacetan', 'Meminta maaf san langsung bekerja seperti biasa', 'Menerima kemarahan dan menjadi malas bekerja', null, '7. SOAL LATIHAN TWK-TIU-TKP.txt', '82'),
    ('337241ac05efd1c3ee6c4b96fb0253a2107c1212', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Saya telah melakukan kesalahan yang berakibat buruk pada saya. Saya akan ...', 'Menyesali kesalahan yang telah saya buat', 'Menerima akibat perbuatan saya dengan penuh kesadaran', 'Menerima akibat perbuatan saya dengan sedikit penyesalan', 'Menyalahkan orang lain karena tidak mengingatkan saya', 'Berusaha untuk tidak mengulangi kesalahan tersebut', null, '7. SOAL LATIHAN TWK-TIU-TKP.txt', '83'),
    ('4d3d5cb4c94cc854200049b01f05818ac60039bd', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Biasanya saya menyelesaikan tugas - tugas yang diberikan kepada saya dengan ...', 'Hasil yang paling maksimal dari kemampuan saya', 'Hasil yang kurang baik', 'Hasil yang sangat memuaskan', 'Hasil yang cukup baik dengan sedikit kekurangan yang biasa', 'Hasil yang sesuai standar ker ja teman-teman yang lain', null, '7. SOAL LATIHAN TWK-TIU-TKP.txt', '84'),
    ('6174366127537bc48f707a61e3c54c96f677408a', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Ketika muncul suatu masalah dalam pekerjaan yang saya lakukan, saya akan...', 'Bertanggung jawab', 'Berusaha mencari kambing hitam', 'Tidak mau terlibat', 'Berusaha mencari sumber masalah dan pemecahannya', 'Membiarkan masalah tersebut berlalu dengan sendirinya', null, '7. SOAL LATIHAN TWK-TIU-TKP.txt', '85'),
    ('514599f98a04b8834485548627d52f49b0f3c8d4', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Suatu hari saya telah mengingkari janji bertemu dengan teman saya. Saya akan...', 'Biasa saj, saya sudah sering ingkar janji', 'Merasa malu karena tidak bisa menepati janji', 'Biasa saja dan segera menghubungi teman saya untuk membuat janji baru', 'Merasa takut akan disalahkan teman saya', 'Merasa bersalah dan kemudian meminta maaf kepada teman saya karena telah mengingkari janji', null, '7. SOAL LATIHAN TWK-TIU-TKP.txt', '86'),
    ('a33d9d57c175db7c0c447bd552b9b85ed81b4804', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Atasan menyuruh saya untuk megikuti sebuah pelatihan pada akhir pekan di luar kota. Padahal saat itu saya sedang menyelesaikan pekerjaan kantor yang mendesak. Saya akan ...', 'Mengikuti pelatihan dan menunda mengerjakan pekerjaan saya', 'Mengikuti pelatihan dan meminta teman untuk menyelesaikan pekerjaan saya', 'Segera menyelesaikan pekerjaan saya dan kemudian mengikuti pelatihan', 'Mengikuti pelatihan sambil membawa pekerjaan saya untuk dikerjakan di tempat pelatihan', 'Menolak dengan halus perintah atasan dan tetap menyelesaikan pekerjaan saya', null, '7. SOAL LATIHAN TWK-TIU-TKP.txt', '87'),
    ('68b5fedebba028da1ea28ea8c7d00a49990591d3', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Saya senang jika orang melihat saya sebagai seseorang yang ...', 'Bertanggung jawab', 'Disiplin', 'Penuh ide-ide baru', 'Berjiwa pemimpin', 'Tidak pernah menyerah', null, '7. SOAL LATIHAN TWK-TIU-TKP.txt', '88'),
    ('0e6c251fa3f1b6f6869abfb91f195161bbe5bfce', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Teman kantor saya ingin meminjam uang kepada saya karena membutuhkan biaya untuk kelahiran anaknya. Padahal saat itu keadaan keuangan saya juga sedang menipis. Saya akan ...', 'Mengatakan tidak mempunyai uang', 'Mencarikan pinjaman ke teman kantor yang lain', 'Menyarankannya untuk meminjam kepada teman yang lain', 'Memberi sebagian dari uang yang saya miliki', 'Memberi semua uang yang saya miliki, saya masih bisa meminjam uang kepada orang tua saya', null, '7. SOAL LATIHAN TWK-TIU-TKP.txt', '89'),
    ('d2722b92dae9103e5fad93cf74df754307fb2e04', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Ketika ingin memberi kan hadiah kepada teman saya, saya biasanya mempertimbangkan ...', 'Keadaan keuangan saya', 'Keuangan saya dan keinginan teman saya', 'Kebutuhan teman saya', 'Keinginan teman saya tanpa peduli keuangan saya', 'Keuangan dari hadiah yang saya berikan', null, '7. SOAL LATIHAN TWK-TIU-TKP.txt', '90'),
    ('1d7b40caddf90d91a3630e754336713949b96528', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Saya berhasil mengatasi tantangan terutama karena..', 'Nasib baik ada di tangan saya', 'Saya berani mencoba hal -hal yang tidak berisiko', 'Saya berani mencoba dengan segala risikonya', 'Saya mendapat bantuan dari lingkungan', 'Saya tidak putus asa menghadapi kegagalan', null, '7. SOAL LATIHAN TWK-TIU-TKP.txt', '92'),
    ('1088ebf75682a1f004c62030bccf173862e058ff', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Jika ada kesempatan untuk berkompetisi dalam bidang yang saya senangi, maka saya.', 'Mengalahkan pesaing dengan meningkatkan diri', 'Tidak ikut kompetisi', 'Ikut kalau ada kemungkinan menang', 'Berusaha keras mengalahkan pesaing dengan mencari kelemahan mereka', 'Lebih baik tidak usah ikut karena khawatir akan kalah', null, '7. SOAL LATIHAN TWK-TIU-TKP.txt', '93'),
    ('d24bc2463a2e78e0afd5198fb4ce897199dc4ade', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Ketika Anda membawa anak Anda ke pasar, anak Anda tiba-tiba meminta untuk dibelikan permainan, maka Anda akan...', 'Menolaknya karena harganya mahal', 'Menolaknya karena Anda mau ia membelinya sendiri dengan uang tabungannya', 'Segera membelikannya karena ia memaksa', 'Menolaknya karena hal tersebut tak ada dalam rencana Anda dan dia', 'Mengabulkannya karena Anda takut ia menangis', null, '7. SOAL LATIHAN TWK-TIU-TKP.txt', '94'),
    ('13f67772b9a5bf8d0758307976b87cf35e6b04b9', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Ada tawaran beasiswa belajar keluarnegeri ditempat saya bekerja, sikap saya…', 'Melihat syarat dan pra -syarat untuk mengikutinya', 'Mempersiapkan diri untuk mengikutinya', 'Mendaftarkan diri, karena saya yakin akan kemampuan saya', 'Jika itu bukan bidang saya, saya lebih baik menolaknya', 'Mendaftar dan mempersiapkan diri', null, '7. SOAL LATIHAN TWK-TIU-TKP.txt', '96'),
    ('fd923e3e8ca87ce0b7a1dde63036139d831c256b', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Menurut saya, orang yang kehilangan kesempatan mengembangkan usahanya lebih disebabkan karena mereka..', 'Bertahan pada cara yang telah berjalan', 'Menunggu bantuan pihak lain', 'Pikiran bercabang pada usaha lain', 'Menunda ketika melihat resikonya', 'Mundur, begitu melihat risikonya', null, '7. SOAL LATIHAN TWK-TIU-TKP.txt', '97'),
    ('496186746df5f46c9c2876e1afca4effd6ec65a1', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Jika aturan pada tempat anda bekerja terdapat persyaratan yang membuat anda tidak memungkinkan untuk melanjutkan pendidikan ke tingkat yang lebih tinggi, maka sikap anda...', 'Tetap melanjutkan pendidikan meskipun tidak mendapatkan izin', 'Tetap fokus pada pekerjaan saja sambil menunggu persyaratan terpenuhi', 'Melakukan lobi kepada atasan agar mendapatkan izin', 'Melakukan protes keras dengan alasan menghalangi hak untuk', 'Mengikuti kursus dan pendidikan informal sambil menunggu persyaratan dapat terpenuhi', null, '7. SOAL LATIHAN TWK-TIU-TKP.txt', '98'),
    ('544f5bb6e1d854ba24eeed5145586f96796f56a7', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Menurut Anda, PNS yang baik itu adalah PNS yang...', 'Bekerja untuk memenuhi kebutuhan keluarganya', 'Melayani masyarakat dengan sepenuh hati', 'Bekerja jika ada bayarannya saja', 'Profesional dan jujur dalam bekerja', 'Senang membantu mereka yang sedang kesusahan', null, '7. SOAL LATIHAN TWK-TIU-TKP.txt', '99'),
    ('11ff8e9878b8ee9508406290b57a23329b11a408', 'TKP', 'pengambilan-keputusan', 'sedang', 'draft', 'Saya senang jika rekan saya bisa menjadi rekan kerja yang...', 'Mandiri', 'Senang membantu', 'Profesional', 'Jujur', 'Penuh dedikasi TES WAWASAN KEBANGSAAN', null, '7. SOAL LATIHAN TWK-TIU-TKP.txt', '100'),
    ('887542fe4624cccf90cc54dc36f5805f4c20a6fb', 'TWK', 'wawasan-kebangsaan', 'sedang', 'draft', 'Berikut ini ciri-ciri ideologi tertutup, kecuali ...', 'Bersifat totaliter', 'Pluralisme pandangan dan kebudayaan ditiadakan', 'Menuntut masyarakat untuk memiliki kesetiaan total', 'Tidak diciptakan oleh negara, tetapi ditemukan dalam masyarakat sendiri', 'Isi ideologi tidak hanya nilai -nilai dan cita -cita, tetapi tuntutan konkret dan operasional yang keras, mutlak, dan total.', null, '8. SOAL LATIHAN TWK-TIU-TKP.txt', '1'),
