    ('70b14a1c79346d77c393c31a7267cc01a41342d9', 'TIU', 'logika-analitis', 'sedang', 'draft', '2222 202 ...', '18,0', '18,36', '18,7', '19,0', '19,3 Pembahasan: Pola hubungan antarbilangan adalah pembagian masing-masing bilangan dengan angka 11. 2222 202 18,36 : 3 : 3 Jawaban: B', 'B', 'KISI-KISI SOAL BUMN 2022__BUKU PSIKOTES.txt', '9'),
    ('813d4d52752a1a0283e23462694e9afc2d8b6c52', 'TIU', 'logika-analitis', 'sedang', 'draft', '27 30 ... 45 57 ...', '84 dan 36', '66 dan 39', '36 dan 72', '33 dan 88', '32 dan 86 Pembahasan: Pola hubungan antarbilangan dapat dilihat berdasarkan gambar berikut.', 'E', 'KISI-KISI SOAL BUMN 2022__BUKU PSIKOTES.txt', '10'),
    ('5ecdf21b2aae8ca5344d9749a2bf5b94e0b7e413', 'TIU', 'figural', 'sedang', 'draft', 'Perhatikan gambar berikut! Nilai X dan Y berturut-turut adalah ...', '11 dan 71', '12 dan 21', '71 dan 11', '71 dan 13', '11 dan 72 Pembahasan: Pola hubungan antarbilangan pada gambar pertama adalah operasi pembagian. Perhatikan penjelasan berikut. Pola bilangan dalam lingkaran adalah', 'D', 'KISI-KISI SOAL BUMN 2022__BUKU PSIKOTES.txt', '1'),
    ('282bb9f112feb19a122683ce7435765b5dc1539d', 'TIU', 'figural', 'sedang', 'draft', 'Perhatikan gambar berikut! Nilai X adalah ...', '53', '147', '83', '114', '43 Pembahasan: Pola hubungan antarbilangan pada gambar kedua adalah perkalian angka pertama dengan angka kedua, angka kedua dengan ketiga, dan seterusnya.', 'C', 'KISI-KISI SOAL BUMN 2022__BUKU PSIKOTES.txt', '2'),
    ('22b3afc4bf2d208364ec33379fd80d6a84ee4393', 'TIU', 'figural', 'sedang', 'draft', 'Perhatikan gambar berikut! Nilai Y adalah ...', '2', '4', '5', '8', '10 Pembahasan: Pola hubungan antarbilangan pada gambar kedua adalah operasi pembagian. Angka ketiga dibagi oleh angka pertama menghasilkan angka kedua.', 'A', 'KISI-KISI SOAL BUMN 2022__BUKU PSIKOTES.txt', '3'),
    ('fda12b2ae76e215148348fb029da2aed31fa610e', 'TIU', 'figural', 'sedang', 'draft', 'Perhatikan gambar berikut! Nilai Y dan X berturut-turut adalah ...', '64 dan 9', '0 dan 69', '23 dan 0', '87 dan 56', '32 dan 43 41Ragam Materi Tes dalam Psikotes Pembahasan: Susunan bilangan pada gambar pertama memiliki pola penggunaan operasi pembagian. Bilangan per - tama dibagi dengan angka kedua menghasilkan angka ketiga. Angka ketiga dibagi dengan angka keempat menghasilkan angka kelima.', 'E', 'KISI-KISI SOAL BUMN 2022__BUKU PSIKOTES.txt', '10'),
    ('1cf66a1c043715d7a51d11b6e0b0dea516005bce', 'TIU', 'logika-analitis', 'sedang', 'draft', '3log 9 = ...', '3', '2', '1', '4', '5 Pembahasan: 3log 9 = 3log 32 = 2 Jawaban: B', 'C', 'KISI-KISI SOAL BUMN 2022__BUKU PSIKOTES.txt', '2'),
    ('71d906986cc8650f6905cb841188ba64a4409b97', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Bentuk logaritma dari 3 5 = 243 yang tepat adalah ...', '4log 243 = 3', '2log 243 = 5', '3log 243 = 5', '4log 343 = 2', '1log 343 = 5 Pembahasan:', 'A', 'KISI-KISI SOAL BUMN 2022__BUKU PSIKOTES.txt', '3'),
    ('575225867dd9c102efcc9575a22b65297a2c1621', 'TIU', 'logika-analitis', 'sedang', 'draft', '5log 125 = ...', '2', '5', '4', '3', '6 Pembahasan: 5log 125 = 5log 53 = 3 Jawaban: D', 'E', 'KISI-KISI SOAL BUMN 2022__BUKU PSIKOTES.txt', '4'),
    ('cd9871f51e276568a8fb1ed1802d043ff99c9871', 'TIU', 'logika-analitis', 'sedang', 'draft', 'log 1.000.000 = ...', '4', '5', '8', '7', '6 Pembahasan: log 1.000.000 = log 106 = 6 Jawaban: E 43Ragam Materi Tes dalam Psikotes', 'A', 'KISI-KISI SOAL BUMN 2022__BUKU PSIKOTES.txt', '5'),
    ('785d61fa3b4ebd160f8f02b453859e76731eea13', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Jika 3log 27 = a, maka blog a = 1. Nilai b yang tepat adalah ...', '2', '9', '3', '4', '5 Pembahasan: 3log 27 = 3log 33 = 3 a = 3, nilai ini dimasukkan ke dalam persamaan yang kedua. blog a = 1 blog 3 = 1 → b1 = 3 b = 3 Jadi, nilai b adalah 3. Jawaban: C', 'A', 'KISI-KISI SOAL BUMN 2022__BUKU PSIKOTES.txt', '6'),
    ('21dc2a48475e8d51061aad2a5803849068e34a8a', 'TIU', 'logika-analitis', 'sedang', 'draft', '2log 16 = ...', '3', '4', '6', '8', '9 Pembahasan: 2log 16 = ... 2log 24 = 4 Jawaban: B', 'C', 'KISI-KISI SOAL BUMN 2022__BUKU PSIKOTES.txt', '7'),
    ('74ae64bb256200047b5da22971d539f53e49f661', 'TIU', 'logika-analitis', 'sedang', 'draft', '2log 2+ 2log 4 =', '2', '4', '5', '7', '3 Pembahasan: 2log 2+ 2log 4 = 2log (2 × 4) = 2log 8 = 2log 23 = 3 Jawaban: E', 'B', 'KISI-KISI SOAL BUMN 2022__BUKU PSIKOTES.txt', '8'),
    ('e1a9bb1a1cea123f47449841155382b746c64d35', 'TIU', 'logika-analitis', 'sedang', 'draft', '5 log = ...', '2', '1', '4', '3', '5 Pembahasan: 5log = 5log 625 – 5log 125 = 5log 54 – 5log 53 = 4 – 3 = 1 Jawaban: B', 'B', 'KISI-KISI SOAL BUMN 2022__BUKU PSIKOTES.txt', '9'),
    ('933fe3e5f48dde42b3ef65ff07e96dba99c6a202', 'TIU', 'logika-analitis', 'sedang', 'draft', '4log 1 = ....', '3', '2', '1', '0', '5 Pembahasan: 4log 1 = 4log 40 = 0 Jawaban: D', 'E', 'KISI-KISI SOAL BUMN 2022__BUKU PSIKOTES.txt', '10'),
    ('550adeb2a113f1ef8c3eb1ca65034ef7ac3695d0', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Upi mencuci menggunakan deter gen. Upi memberi pewangi pakaian pada bilasan terakhir saat dia mencuci.', 'Upi menggunakan detergen dan pewangi pakaian saat mencuci.', 'Upi memberi pewangi pakaian dan detergen pada bilasan terakhir saat dia mencuci.', 'Upi memberi pewangi pakaian pada bilasan terakhir tanpa detergen.', 'Upi menggunakan detergen tanpa pewangi pakaian.', 'Tidak ada kesimpulan Pembahasan: Pernyataan-pernyataan tersebut memi liki kesamaan dalam subjek nya, sehingga tidak bisa dilakukan penia- daan atau mencoret bagian tersebut. Kesimpulan adalah gabungan dua pernyataan tersebut, yaitu Upi menggunakan detergen dan pewangi saat mencuci pakaian. Jawaban: A', 'D', 'KISI-KISI SOAL BUMN 2022__BUKU PSIKOTES.txt', '1'),
    ('820663eac9702de4f3c8913bd3bc41f449be66ac', 'TIU', 'silogisme', 'sedang', 'draft', 'Semua pegawai negeri berangkat kerja pukul tujuh pagi. Nani berangkat kerja pukul sembilan pagi.', 'Nani seorang pegawai negeri.', 'Semua pegawai negeri be rangkat kerja pukul tujuh pagi kecuali Nani.', 'Nani bukan seorang pegawai negeri.', 'Nani berangkat kerja pukul sembilan dan tetap seorang pegawai negeri.', 'Pegawai negeri boleh berangkat pukul sembilan. 47Ragam Materi Tes dalam Psikotes Pembahasan: Nani berangkat kerja pukul sembilan pagi, sedangkan pegawai negeri harus berangkat kerja pukul tujuh pagi. Dapat disimpulkan bahwa Nani bukan seorang pegawai negeri, karena jika Nani adalah seorang pegawai negeri, dia akan berangkat pukul tujuh pagi. Jawaban: C', 'C', 'KISI-KISI SOAL BUMN 2022__BUKU PSIKOTES.txt', '2'),
    ('39aba77ae5ff33e0816b5594b29949bf76b6057a', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Jika Fida tidur siang menggunakan bantal, maka dia akan tidur dengan nyenyak. Jika Fida tidur dengan nyenyak, maka boneka beruang itu pasti menjadi gulingnya.', 'Jika Fida tidur dengan nyenyak, maka dia pasti menggunakan bantal dan guling.', 'Fida akan tidur semakin nyenyak jika menggunakan bantal dan boneka beruang sebagai gulingnya.', 'Fida tidak bisa tidur nyenyak jika tidak ada boneka beruang.', 'Jika Fida tidur menggunakan bantal saja, maka dia tidak akan nyenyak.', 'Jika Fida tidur siang meng gunakan bantal, maka boneka beruang itu pasti menjadi gulingnya. Pembahasan: Untuk mengerjakan tipe soal ini, gunakan logika matematika Modus Silogisme. Jika Fida tidur siang menggunakan bantal (p), maka dia akan tidur dengan nyenyak (q). Jika Fida tidur dengan nyenyak (q), maka boneka beruang itu pasti menjadi gulingnya (r). Premis 1 : p → q Premis 2 : q → r Kesimpulan: p → r Kesimpulannya adalah p → r atau Jika Fida tidur siang menggunakan bantal, maka boneka beruang itu pasti menjadi gulingnya. Jawaban: E', 'A', 'KISI-KISI SOAL BUMN 2022__BUKU PSIKOTES.txt', '3'),
    ('fe12e437a8fc24ab24eac767a8422f333f6c6553', 'TIU', 'silogisme', 'sedang', 'draft', 'Semua pelajar yang belajar dengan rajin mendapatkan hasil Ujian Nasional (UN) yang bagus. Andi tidak mendapatkan nilai ujian yang memuaskan.', 'Ada sebagian anak yang tidak mendapatkan nilai bagus pada Ujian Nasional.', 'Semua pelajar ingin men dapatkan nilai ujian yang memuaskan, termsuk Andi.', 'Andi sudah belajar dengan rajin, tetapi tetap mendapatkan nilai ujian yang tidak bagus.', 'Andi mendapatkan nilai Ujian Nasional yang bagus.', 'Andi tidak belajar dengan rajin. Pembahasan: Untuk mengerjakan tipe soal ter sebut, gunakan logika matematika Modus Tollens. Semua pelajar yang belajar dengan rajin (p) mendapatkan hasil Ujian Nasional (UN) yang bagus (q). Andi tidak mendapatkan nilai ujian yang memuaskan (~q).', 'E', 'KISI-KISI SOAL BUMN 2022__BUKU PSIKOTES.txt', '4'),
    ('7135079c40e41d4d1d56fbbcb6bf407a21e4c8f0', 'TIU', 'silogisme', 'sedang', 'draft', 'Semua anak perempuan suka cokelat. Risa suka buah stroberi.', 'Risa tidak suka cokelat.', 'Risa berbeda dengan perempuan lain yang suka makan cokelat.', 'Risa suka buah stroberi dan cokelat.', 'Semua anak perempuan ter ma suk Risa suka dengan cokelat.', 'Sebagian anak suka cokelat, tetapi tidak suka stroberi. Pembahasan: Semua anak perempuan suka cokelat. Risa suka buah stroberi (Risa seorang 49Ragam Materi Tes dalam Psikotes anak perempuan). Kesimpulan dari pernyataan di atas adalah Risa suka buah stroberi dan cokelat. Jawaban: C', 'A', 'KISI-KISI SOAL BUMN 2022__BUKU PSIKOTES.txt', '6'),
    ('5ad25adafd9c98799e349ae58ace849a6133efa7', 'TIU', 'silogisme', 'sedang', 'draft', 'Semua nelayan di daerah pesisir laut selalu berprofesi sebagai pedagang ikan di pasar. Sebagian nelayan menjual terasi udang di pasar.', 'dan B, sehingga fokusnya pada lingkaran B (ingat, B merupakan bagian A). Kesimpulannya adalah sebagian nelayan merupakan pedagang ikan di pasar dan menjual terasi udang. Atau, dapat dinyatakan dengan kalimat berikut: Selain berprofesi sebagai pedagang ikan di pasar, sebagian nelayan juga menjual terasi udang.', 'Selain berprofesi sebagai peda- gang ikan di pasar, sebagian nelayan juga menjual terasi udang.', 'Tidak semua nelayan menjual terasi udang di pasar.', 'Sebagian nelayan hanya berprofesi sebagai pedagang ikan.', 'Hanya sedikit nelayan yang menjual terasi udang. Pembahasan: Ingat tips dan trik yang telah dijelaskan sebelumnya. Jika ada tipe soal seperti ini, pusatkan perhatian Anda pada kalimat “sebagian...........”. Sebagian nelayan menjual terasi udang di pasar, dan semua nelayan adalah pedagang ikan di pasar. Hal ini menunjukkan ada sebagian nelayan yang menjual ikan dan terasi udang, sedangkan yang lain hanya menjual ikan saja. Atau, dapat dinyatakan dengan kalimat berikut: Selain berprofesi sebagai pedagang ikan di pasar, sebagian nelayan juga menjual terasi udang. Pernyataan C (Tidak semua nelayan menjual terasi udang di pasar) sebenarnya juga merupakan pernyataan yang benar. Namun, pernyataan ini bukanlah kesimpulan karena hanya mewakili pernyataan kedua. Jawaban: B Soal ini dapat juga dibuat diagram venn seperti gambar berikut. A: Semua nelayan adalah pedagang ikan di pasar. B: Sebagian nelayan menjual terasi udang. Kesimpulan harus mewakili lingkaran', 'C', 'KISI-KISI SOAL BUMN 2022__BUKU PSIKOTES.txt', '7'),
    ('0a97dc48cf487d30c2de196129d676a7545b1b89', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Toko itu menyediakan berbagai jenis gaun untuk berbagai jenis acara. Gaun pengantin berwarna putih digantung pada salah satu etalase di toko tersebut.', 'Toko itu menjual gaun pe ngantin berwarna putih.', 'Toko itu menyediakan berbagai jenis gaun untuk berbagai jenis acara, salah satunya adalah gaun pengantin.', 'Toko itu menyediakan berbagai jenis gaun yang digantung di etalase toko.', 'Toko itu menyediakan gaun se- suai jenis acaranya.', 'Gaun yang disediakan toko itu digantung dalam etalase. Pembahasan: Soal ini merupakan tipe soal “Semua ... Sebagian ...”. Kesimpulan yang mewakili kedua penyataan tersebut adalah gaun pengantin dan berbagai jenis gaun untuk berbagai jenis acara dijual di toko tersebut, atau dapat dinyatakan dengan kalimat berikut: Toko menyediakan berbagai jenis gaun untuk berbagai jenis acara, salah satunya adalah gaun pengantin. Pernyataan C dan D merupakan pernyataan yang benar sesuai dengan kedua pernyataan yang disebutkan, tetapi bukan merupakan kesimpulan karena tidak mewakili kedua pernyataan. Jawaban: B', 'B', 'KISI-KISI SOAL BUMN 2022__BUKU PSIKOTES.txt', '9'),
    ('4659f0c28f2a2fb7656de455cbfdeabb7496559e', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Yogyakarta menjadi salah satu daerah yang menjadi tujuan utama para turis mancanegara. Malioboro adalah salah satu tempat wisata yang dipenuhi dengan turis mancanegara.', 'Turis mancanegara yang ber - wisata ke Yogyakarta memenuhi jalanan Malioboro.', 'Malioboro adalah salah satu tempat wisata di Yogyakarta yang menjadi tujuan utama para turis.', 'Turis mancanegara suka me ngun- jungi Malioboro di Yogyakarta. 51Ragam Materi Tes dalam Psikotes', 'Salah satu tempat wisata di Yogyakarta adalah Malioboro.', 'Tempat wisata yang dipenuhi para turis di Yogyakarta adalah Malioboro. Pembahasan: Kalimat “... yang dipenuhi dengan turis mancanegara” pada pernyataan kedua merupakan kalimat yang memiliki makna yang sama dengan kalimat “... yang menjadi tujuan utama para turis mancanegara” pada pernyataan pertama. Kedua pernyataan ini dapat diubah menjadi sebagai berikut. Yogyakarta menjadi salah satu daerah yang menjadi tujuan utama para turis mancanegara. Malioboro adalah salah satu tempat wisata yang menjadi tujuan utama para turis mancanegara. Kesimpulan dari kedua pernyataaan tersebut adalah penggabungan bagian kalimat yang tidak dicoret, yaitu Malioboro menjadi salah satu tempat wisata di Yogyakarta, atau bisa juga dinyatakan dengan kalimat berikut: Salah satu tempat wisata di Yogyakarta adalah Malioboro. Jawaban: D', 'E', 'KISI-KISI SOAL BUMN 2022__BUKU PSIKOTES.txt', '10'),
    ('01cf9c61998f8fbd69db5ff015b680f38ae13679', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Berapa kali setiap orang memiliki tugas menyapu dalam setiap minggunya?', 'Dua kali', 'Tiga kali', 'Empat kali', 'Lima kali', 'Enam kali Pembahasan: Berdasarkan tabel jadwal piket, setiap orang menyapu lima kali dalam seminggunya. Jawaban: D', 'D', 'KISI-KISI SOAL BUMN 2022__BUKU PSIKOTES.txt', '1'),
    ('f65917295d356ae15d7aeab3150096a176a342ed', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Kapan saat Rini dan Rida memiliki tugas menyapu bersama-sama?', 'Kamis dan Sabtu', 'Jumat dan Minggu', 'Kamis dan Jumat', 'Senin dan Selasa', 'Selasa dan Kamis Pembahasan: Berdasarkan tabel jadwal piket, Rini dan Rida memiliki tugas bersama- sama pada hari Kamis dan Jumat. Jawaban: C', 'C', 'KISI-KISI SOAL BUMN 2022__BUKU PSIKOTES.txt', '2'),
    ('2b3f8f89fa86ccbbe7738925e3420c81fde0b561', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Jika pada hari Senin dan Selasa Rida sakit, siapa yang harus melakukan piket seorang diri?', 'Rini dan Rina', 'Rini', 'Rina', 'Rini dan Rida', 'Tidak ada yang piket seorang diri Pembahasan: Pada hari Selasa Rida tidak memiliki tugas menyapu. Jika pada hari Senin dan Selasa Rida sakit, maka yang akan melakukan piket sendirian pada hari Senin adalah Rina. Jawaban: C', 'A', 'KISI-KISI SOAL BUMN 2022__BUKU PSIKOTES.txt', '3'),
    ('71688b78463e84b5331e3b85bb0d3e96490827bb', 'TIU', 'logika-analitis', 'sedang', 'published', 'Jika jadwal kuliah Rini hari Senin minggu ini diubah menjadi hari Sabtu, apa yang akan terjadi?', 'Rina akan piket sendirian', 'Rina akan piket bersama Rida', 'Rini akan piket sendirian setelah kuliah usai', 'Rini dan Rida tetap akan piket bersama', 'Tidak ada yang piket pada hari Senin minggu ini', 'E', 'KISI-KISI SOAL BUMN 2022__BUKU PSIKOTES.txt', '4'),
    ('a80aa66f3e8dcdb0ab28b00938994ac9e5eca160', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Harga parfum X lebih mahal daripada parfum Y . Harga parfum Z dua kali lipat dari harga parfum Y dan tidak melebihi harga parfum X.', 'Parfum Z memiliki harga yang paling mahal.', 'Harga parfum Z lebih mahal daripada harga parfum X.', 'Parfum Y memiliki harga yang paling murah.', 'Parfum X lebih murah daripada harga parfum Y .', 'Parfum X memiliki harga paling murah. Pembahasan: Urutan harga parfum dari yang paling tinggi ke rendah adalah X–Z–Y Dengan demikian, Parfum Y memiliki harga yang paling murah. Jawaban: C Soal nomor 6–9 berdasarkan informasi di bawah ini: Perpustakaan kampus menyediakan berbagai macam buku yang dikelom- pokkan ke dalam berbagai kate gori, yaitu buku ilmu murni, ilmu terapan, dan buku fiksi. Ketiga kategori tersebut disusun dalam tiga rak dengan ketentuan sebagai berikut: Rak buku ilmu murni terletak di sebelah ▪ kiri rak buku fiksi dengan jarak enam langkah kaki. Rak buku ilmu terapan di sebelah ▪ kanan rak buku fiksi dengan jarak empat langkah kaki. Rak buku fiksi berada di kiri sebuah ▪ meja dan kursi dengan jarak sepuluh langkah kaki. Pembahasan: Urutan rak buku ilmu murni (M), ilmu terapan (T), buku fiksi (F), dan meja kursi (MK) dari kiri ke kanan dengan jarak tertentu adalah sebagai berikut:', 'A', 'KISI-KISI SOAL BUMN 2022__BUKU PSIKOTES.txt', '5'),
    ('680ea2b07329bc8af34eaced2786f59f61e27eff', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Urutan rak buku ilmu murni, ilmu terapan, fiksi, dan meja kursi dari kiri ke kanan yang benar adalah:', 'Murni-Terapan-Meja Kursi-Fiksi', 'Murni-Fiksi-Terapan-Meja Kursi', 'Terapan-Fiksi-Murni-Meja Kursi', 'Fiksi-Terapan-Murni-Meja Kursi', 'Meja Kursi-T erapan-Fiksi-Murni Pembahasan: Urutan rak buku ilmu murni (M), ilmu terapan (T), buku fiksi (F), dan meja kursi (MK) dari kiri ke kanan adalah Murni-Fiksi-Terapan-Meja Kursi. Jawaban: B', 'A', 'KISI-KISI SOAL BUMN 2022__BUKU PSIKOTES.txt', '6'),
    ('6141d76b1e03d2980741a7fd0aaea3c1a21552cb', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Jika Lukman yang sedang duduk di kursi ingin mengambil buku ilmu murni, berapa jarak yang harus ditempuh?', 'Delapan langkah kaki', 'Empat langkah kaki', 'Enam belas langkah kaki', 'Sepuluh langkah kaki', 'Dua belas langkah kaki 55Ragam Materi Tes dalam Psikotes Pembahasan: Jarak yang harus ditempuh Lukman adalah 6 + 4 + 6 = 10 langkah kaki. Jawaban yang tepat adalah enam belas langkah kaki. Jawaban: C', 'C', 'KISI-KISI SOAL BUMN 2022__BUKU PSIKOTES.txt', '7'),
    ('315206f5327c89840418ba04d8cb53faa99dab2b', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Jika rak buku ilmu terapan dan rak buku fiksi ditukar, berapa jarak antara rak buku fiksi dengan meja dan kursi?', 'Dua belas langkah kaki', 'Enam langkah kaki', 'Empat langkah kaki', 'Delapan langkah kaki', 'Enam belas langkah kaki Pembahasan: Jika rak buku ilmu terapan dan rak buku fiksi ditukar, maka susunan rak- rak tersebut adalah: Jarak antara rak meja buku fiksi dengan meja kursi adalah enam langkah kaki. Jawaban: B', 'B', 'KISI-KISI SOAL BUMN 2022__BUKU PSIKOTES.txt', '8'),
    ('f59215d605a89dc1006f28025a8f2a7f54bc3492', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Jika rak buku ilmu terapan dipindahkan enam langkah ke arah kiri, bagaimanakah susunan rak buku dari kiri ke kanan?', 'Murni-Terapan-Fiksi-Meja Kursi', 'Terapan-Murni-Fiksi-Meja Kursi', 'Fiksi-T erapan-Murni-Meja Kursi', 'Meja Kursi-Murni-Terapan-Fiksi', 'Terapan-Fiksi-Meja Kursi Pembahasan: Jika rak buku ilmu terapan dipindahkan enam langkah ke arah kiri, susunan rak tersebut adalah: Jadi susunan rak buku dari kiri ke kanan adalah Murni-Terapan-Fiksi-Meja Kursi. Jawaban: A', 'B', 'KISI-KISI SOAL BUMN 2022__BUKU PSIKOTES.txt', '9'),
    ('0ba4fdb5fb9a92e51e8a6cc420d183c64fc1c098', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Lampu 5 watt merek X lebih terang daripada lampu 5 watt merek Z. Lampu 5 watt merek Y kurang terang dibandingkan lampu Z.', 'Lampu merek X adalah lampu yang paling terang dibandingkan yang lain.', 'Lampu merek Z kurang terang dibandingkan lampu merek Y .', 'Ketiga lampu memiliki daya yang sama.', 'Lampu merek Z lebih terang daripada lampu merek X.', 'Lampu merek Z paling redup dibandingkan yang lain. Pembahasan: Urutan lampu dari yang memiliki cahaya paling terang: X–Z–Y Dengan demikian, jawaban yang paling benar adalah: Lampu merek X adalah lampu yang paling terang dibandingkan yang lain. Jawaban: A', 'E', 'KISI-KISI SOAL BUMN 2022__BUKU PSIKOTES.txt', '10'),
    ('c8edaa8b6c308ed4faab1d77391b91e77d901c0b', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Penulisan nama berikut yang benar adalah ...', 'Arsi awaliyah', 'Arsi Awaliyah', 'A Awaliyah', 'arsi awaliyah', 'ARSI AWALIYAH Pembahasan: Penulisan nama harus diawali huruf kapital di setiap unsur katanya dan untuk nama yang disingkat diakhiri dengan tanda titik. Jawaban: B', 'D', 'KISI-KISI SOAL BUMN 2022__BUKU PSIKOTES.txt', '1'),
    ('616314a7b82fd22e07431b003c618000ee3f2d83', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Penulisan gelar yang benar adalah ...', 'Joko Suranto. M. Si', 'Joko Susanto, MSi', 'Joko Susanto, M.Si', 'Joko Susanto . MSi', 'Joko Susanto, M. Si. Pembahasan: Dalam menuliskan gelar seseorang terdapat beberapa syarat, antara lain: (1) Penulisan gelar akademik di belakang nama harus diawali dengan koma. (2) Gelar akademik di belakang nama diawali dengan huruf besar dan dilanjutkan dengan titik setelah huruf pertama, kemudian dilanjutkan dengan huruf besar kembali. (3) Di akhir gelar tidak diakhiri dengan tanda titik. Dengan demikian, jawaban yang tepat untuk soal ini adalah C. Jawaban: C', 'C', 'KISI-KISI SOAL BUMN 2022__BUKU PSIKOTES.txt', '2'),
    ('473f058b97ff565f817fd1065443fa6007699347', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Banyaknya pembangunan aparte men menimbulkan kontroversi di kalangan masyarakat. Kalimat inti dari kalimat tersebut adalah ...', 'Pembangunan menimbulkan kon - troversi masyarakat.', 'Kalangan masyarakat tidak senang dengan pembangunan apartemen.', 'Pembangunan apartemen me ru- gikan masyarakat.', 'Pembangunan apartemen me- nimbulkan kontroversi.', 'Kontroversi ditimbulkan oleh pembangunan apartemen. Pembahasan: Kalimat inti merupakan kalimat yang dapat mewakili keseluruhan kalimat. Dari seluruh jawaban di atas, yang dapat mewakili keseluruhan kalimat 57Ragam Materi Tes dalam Psikotes adalah pem bangunan apartemen menimbulkan kontroversi. Jawaban: D', 'A', 'KISI-KISI SOAL BUMN 2022__BUKU PSIKOTES.txt', '3'),
    ('bc07f172346c3bb8da5de847be1a0097ebd56f82', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Berikut ini adalah ciri-ciri surat resmi, kecuali ...', 'Menggunakan bahasa baku', 'Terdapat nomor surat', 'Dikeluarkan oleh instansi', 'Berisi keperluan instansi', 'Ditujukan kepada keluarga Pembahasan: Surat resmi biasanya ditujukan dari instansi kepada instansi atau orang yang berkepentingan dengan instansi tersebut, bukan ditujukan untuk keluarga ataupun teman. Jawaban: E', 'E', 'KISI-KISI SOAL BUMN 2022__BUKU PSIKOTES.txt', '4'),
    ('1e138d17a77e8eacec3ee535fc11ba63da4d82a1', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Penulisan kalimat langsung yang benar adalah ...', 'Ibu berpesan, “Kamu jangan lupa ibadah.”', 'Ibu berpesan untuk tidak lupa beribadah.', 'Ibu “Kamu jangan lupa ibadah.”', 'Ibu berpesan, “Kamu jangan lupa ibadah”.', 'Kamu jangan lupa ibadah, “pesan ibu.” Pembahasan: Syarat kalimat langsung adalah: • Jika diawali dengan kata peng- antar dilanjutkan dengan koma terlebih dahulu kemudian tanda petik. • Setelah kalimat langsung selesai diakhiri dengan tanda baca baru tanda petik tutup. Jadi, dari soal di atas jawaban yang paling mewakili syarat tersebut adalah Ibu berpesan, “Kamu jangan lupa ibadah.” Jawaban: A', 'A', 'KISI-KISI SOAL BUMN 2022__BUKU PSIKOTES.txt', '5'),
    ('0df34dfb51611e25e66df48a63bbbdb86e4de5cf', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Penulisan NIP (Nomor Induk Pegawai) yang benar adalah ...', 'NIP 1988 12 10 654 321 1 000', 'NIP 1988 1210 654 321 1 000', 'NIP 19881210 6543211000', 'NIP 19881210654321 1000', 'NIP 1988 1210 654321 1000 Pembahasan: Penulisan nomor induk adalah 16 digit yang terdiri dari tahun kelahiran, bulan lahir, tanggal lahir, dan dilanjutkan kode instansi maupun nomor. Jadi, jawaban yang paling tepat adalah NIP 19881210654321 1000 Jawaban: D', 'A', 'KISI-KISI SOAL BUMN 2022__BUKU PSIKOTES.txt', '6'),
    ('fd0d7b14eedf0e7ffb7f4aa2cabc4cd67897a962', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Penulisan alamat surat yang benar adalah ...', 'Sinta Ashari Jln. Anggrek no. 15 Jakarta', 'Sinta Ashari Jalan Anggrek no. 15 Jakarta.', 'Sinta Ashari, Jalan Anggrek no. 15 Jakarta', 'Sinta Ashari Jln Anggrek no. 15, Jakarta', 'Sinta Ashari. Jln. Anggrek, no. 15 Jakarta Pembahasan: Dalam penulisan alamat surat yang baku diawali dengan nama orang yang dituju tanpa titik atau koma.', 'C', 'KISI-KISI SOAL BUMN 2022__BUKU PSIKOTES.txt', '7'),
    ('b255d9f67f93b834a3d9af7e18472e7b708050ab', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Sinta berbicara keras-keras supaya seluruh isi aula mendengarnya. Makna kata berulang pada kalimat di atas sama dengan kata berulang pada kalimat ...', 'Kamu-kamu tidak boleh ber bicara sembarangan.', 'Ibu membeli sayur mayur di pasar', 'Intan menangis berkali-kali karena jatuh', 'Asri memeluk adiknya erat- erat karena sudah lama tidak bertemu.', 'Anak-anak bermain di lapangan dekat rumah. Pembahasan: Kata keras-keras dalam soal tersebut bermakna sangat keras, dan erat-erat bermakna sangat erat. Maka kedua kata berulang tersebut memiliki makna yang sama, yaitu sangat. Jawaban: D', 'B', 'KISI-KISI SOAL BUMN 2022__BUKU PSIKOTES.txt', '8'),
    ('cef74f1986696a2469b1dd0b386efeccaa5b063a', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Ani berpesan kepada adiknya, “ Jangan lupa mengerjakan PR.” Bentuk kalimat tak langsung dari kalimat langsung di atas adalah ...', 'Jangan lupa mengerjakan PR, pesan Ani kepada adiknya.', 'Ani berpesan kepada adiknya, jangan lupa mengerjakan PR.', 'Adiknya diberi pesan oleh Ani, jangan lupa mengerjakan PR.', 'Ani berpesan jangan lupa mengerjakan PR adiknya.', 'Ani berpesan kepada adiknya supaya tidak lupa mengerjakan PR. Pembahasan: Bentuk kata tak langsung tidak semata-mata hanya menghilangkan tanda petik pada kalimat lang sungnya. Sesungguhnya, kalimat tak langsung menjelaskan apa inti dari kalimat langsung yang diberikan tersebut. Jadi, jawaban yang tepat adalah Ani berpesan kepada adiknya supaya tidak lupa mengerjakan PR. Jawaban: E', 'B', 'KISI-KISI SOAL BUMN 2022__BUKU PSIKOTES.txt', '9'),
    ('d232b10eedc01b46e3732ada98ccc26bccceff39', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Pemenggalan kata yang benar adalah ...', 'Ke-ke-ra-san', 'Ke-ke-ras-an', 'Ke-ker-as-an', 'Ke-keras-an', 'Ke-kera-san Pembahasan: Untuk memenggal kata harus diketa hui terlebih dahulu kata dasarnya. Setelah mengetahui kata dasarnya, baru kata tersebut dipenggal sesuai suku katanya. Kata dasar dari kekerasan adalah keras, sehingga pemenggalan yang benar adalah ke-ke-ras-an. Jawaban: B 59Ragam Materi Tes dalam Psikotes', 'E', 'KISI-KISI SOAL BUMN 2022__BUKU PSIKOTES.txt', '10'),
    ('79091c530118d70d04c99045681a52f28f20cd6f', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Cita-cita hukum dasar Negara RI terangkum dalam ...', 'Ketetapan dan keputusan Presiden beserta para menteri', 'Empat pokok pikiran dalam pembukaan UUD 1945', 'Keputusan MPR/DPR', 'Konsepsi hukum dasar yang sangat fundamental', 'Pidato kenegaraan Presiden menjelang 12 Agustus Pembahasan: Cita-cita hukum Negara Kesatuan Republik Indonesia (NKRI) terangkum dalam empat pokok pikiran dalam Pembukaan UUD 1945. Jawaban: B', 'D', 'KISI-KISI SOAL BUMN 2022__BUKU PSIKOTES.txt', '1'),
    ('71d33fe52332f6689a63a941d6c60501a3f436c6', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Prinsip berikut yang sesuai dengan ideologi liberalisme adalah ...', 'Seluruh perekonomian seluruh- nya terpimpin dari pusat', 'Agama tidak diperlukan karena dianggap sebagai candu', 'Masyarakat hanya mengenal satu macam tingkat kelas sosial', 'Hak-hak politik rakyat terke kang, rakyat hanyalah objek', 'Usaha perekonomian diserahkan sepenuhnya kepada individu Pembahasan: Ideologi liberalisme adalah suatu paham yang memberikan kebebasan kepada setiap warga untuk berusaha dan berkarya dengan seluas-luas - nya. Sebagai contoh yaitu usaha perekonomian diserahkan sepenuhnya kepada individu. Jawaban: E', 'C', 'KISI-KISI SOAL BUMN 2022__BUKU PSIKOTES.txt', '2'),
    ('b29066dd353ddde88d2a1ae838d5e8ca7ded1737', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Panitia Persiapan Kemerdekaan Indonesia (PPKI) dibentuk pada ...', '17 Agustus 1945', '18 Agustus 1945', '27 Agustus 1945', '5 Agustus 1945', '7 Agustus 1945 Pembahasan: PPKI dibentuk pada tanggal 7 Agustus 1945 Jawaban: E', 'A', 'KISI-KISI SOAL BUMN 2022__BUKU PSIKOTES.txt', '3'),
    ('9cc9528fb879c32e6c55d90adac8c38c6ee99d2c', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Hak asasi manusia dalam kehi dupan berbangsa dapat dilihat dalam bentuk ...', 'Menyatakan pendapat dan ber or- ganisasi', 'Membuat peraturan daerah', 'Menghormati kebebasan ber - agama', 'Menentukan kerja sama dengan negara lain', 'Membuat organisasi antar daerah Pembahasan: Perwujudan hak asasi manusia dalam kehidupan berbangsa dilihat dalam menyatakan pendapat dan berorganisasi. Jadi, jawaban yang tepat adalah A. Jawaban: A', 'E', 'KISI-KISI SOAL BUMN 2022__BUKU PSIKOTES.txt', '4'),
    ('4b344c2afcf76cdac2f1a873695c967cc7711b10', 'TWK', 'wawasan-kebangsaan', 'sedang', 'draft', 'Rumusan Pancasila terdapat dalam ...', 'UUD 1945', 'Jakarta Charter', 'Preambule UUD 1945', 'Proklamasi 17 Agustus 1945', 'Konsepsi hukum wilayah Pembahasan: Rumusan Pancasila terdapat dalam UUD 1945 Jawaban: A', 'A', 'KISI-KISI SOAL BUMN 2022__BUKU PSIKOTES.txt', '5'),
    ('00f7bfe1dbf61700851f93659bd8ca94c8ec6dfa', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Ciri-ciri patriotisme adalah, kecuali ...', 'Mencintai persatuan dan kesa- tuan wilayah negara', 'Mendahulukan kepentingan ne - ga ra di atas kepentingan pri badi', 'Cinta tanah air dan rela ber korban untuk bangsa', 'Mengembangkan sikap persa tuan dan kesatuan', 'Memperjuangkan otonomi luas yang mengarah pada bentuk federal Pembahasan: Ciri-ciri patriotisme antara lain: • Mencintai persatuan dan kesa- tuan wilayah negara • Mendahulukan kepentingan ne - gara di atas kepentingan pribadi • Cinta tanah air dan rela ber korban untuk bangsa • Mengembangkan sikap persa tuan dan kesatuan Dengan demikan, yang bukan merupakan ciri patriotisme adalah memperjuangkan otonomi luas yang mengarah pada bentuk federal Jawaban: E', 'A', 'KISI-KISI SOAL BUMN 2022__BUKU PSIKOTES.txt', '6'),
    ('ebc6c71f9dd3c3d5faadbddd034f164ff0f7e15f', 'TWK', 'wawasan-kebangsaan', 'sedang', 'draft', 'Dalam kehidupan bernegara, Pancasila berperan sebagai ...', 'Dasar sosial ekonomi', 'Dasar ketatanegaraan', 'Dasar ketatatertiban hukum', 'Dasar kenegaraan', 'Dasar negara Pembahasan: Pancasila merupakan dasar negara. Pancasila pernah ditetapkan sebagai satu-satunya asas dalam berbagai bentuk organisasi, baik massa maupun partai politik, yang saat ini fungsinya kembali sebagai dasar negara. Jawaban: E 61Ragam Materi Tes dalam Psikotes', 'C', 'KISI-KISI SOAL BUMN 2022__BUKU PSIKOTES.txt', '7'),
    ('3c628c1ec0023780f6ac8932d3502a68eb8a9bee', 'TWK', 'wawasan-kebangsaan', 'sedang', 'draft', 'Pemakaian hak milik yang merugikan orang lain berlawanan dengan Pancasila sila ..', 'Ke-1', 'Ke-2', 'Ke-3', 'Ke-4', 'Ke-5 Pembahasan: Pemakaian hak milik yang merugikan orang lain berlawanan dengan Pancasila sila ke-5, yaitu keadilan sosial bagi seluruh rakyat Indonesia. Jawaban: E', 'B', 'KISI-KISI SOAL BUMN 2022__BUKU PSIKOTES.txt', '8'),
    ('79d49c49197f5fd0305f76d986e34180b423ec99', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Panitia Sembilan diketuai oleh ...', 'Ir. Soekarno', 'Moh. Hatta', 'Moh. Yamin', 'Dr. Soepomo', 'Dr. Radjiman Pembahasan: Panitia Sembilan diketuai oleh Ir. Soekarno Jawaban: A', 'B', 'KISI-KISI SOAL BUMN 2022__BUKU PSIKOTES.txt', '9'),
    ('a91fb18896750a4c8dd5c5874264f35ce79ee2f0', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Zaman Kuarter dapat dibedakan atas dua masa, yaitu kala Pleistosen dan ...', 'Holosen', 'Paleolitikum', 'Dilluvium', 'Batu bara', 'Mesolitikum Pembahasan: Zaman Kuarter dibedakan atas: • Dilluvium (zaman Pleistosen) • Alluvium (zaman Holosen) Dengan demikian, jawaban yang tepat adalah Holosen. Jawaban: A', 'D', 'KISI-KISI SOAL BUMN 2022__BUKU PSIKOTES.txt', '1'),
    ('b105c671991fdb099714413646e9cdb62671ce43', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Kata Bhineka Tunggal Ika diambil dari kitab ...', 'Sutasoma', 'Negarakertagama', 'Pararaton', 'Arjuna Wiwaha', 'Mahabharata Pembahasan: Kata Bhinneka Tunggal Ika terdapat pada kitab Sutasoma yang ditulis oleh Mpu Tantular. Jadi, jawaban yang tepat adalah kitab Sutasoma. Jawaban: A', 'A', 'KISI-KISI SOAL BUMN 2022__BUKU PSIKOTES.txt', '5'),
    ('3f4d8e5ba4c5cc166b456091ec20e74af94c7bd3', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Kerajaan Hindu tertua di Indonesia adalah ...', 'Kediri', 'Singasari', 'Kutai', 'Tarumanegara', 'Demak Pembahasan: Kerajaan Hindu tertua di Indonesia adalah Kerajaan Kutai yang berdiri pada 400 M. Jawaban: C', 'A', 'KISI-KISI SOAL BUMN 2022__BUKU PSIKOTES.txt', '6'),
    ('6be73dc38b292044739c5e9a1e689c105887943d', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Zaman Neozoikum berlangsung pada ...', '2.500 juta tahun lalu', '140 juta tahun lalu', '10 juta tahun lalu', 'Kekuasaan', 'Kedudukan sosial Pembahasan: Sejarah awal pembagian kerja dibentuk berdasarkan jenis kelamin. Kaum laki-laki bertugas untuk berburu, dan perempuan bertugas mengasuh anak. Jadi, jawaban yang tepat adalah jenis kelamin. Jawaban: B', 'C', 'KISI-KISI SOAL BUMN 2022__BUKU PSIKOTES.txt', '7'),
    ('da071aa1f3f28c8b09b7848df18b2244d77b0c9c', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Kehidupan berburu dan mengum- pulkan makanan biasa disebut dengan ...', 'Food producing', 'Hunting', 'Food gathering', 'Agriculture', 'Fishing Pembahasan: Kegiatan hidup yang bertujuan memenuhi kebutuhan makan dengan cara berburu dan mengum pulkan makanan disebut food gathering. Jawaban: C', 'A', 'KISI-KISI SOAL BUMN 2022__BUKU PSIKOTES.txt', '3'),
