    ('0657b01d915535896103aec4f8d0f854dd80bf98', 'TIU', 'logika-analitis', 'sedang', 'published', 'Nilai rata-rata ulangan Matematika Nungky, Dila, Ima, Dina, Mia, dan Rifa adalah 79. Jika nilai Nia ditambahkan, rata-rata akan menjadi 81, berapa nilai Matematika Nina?', '81', '79', '93', '70', '80', 'E', 'KISI-KISI SOAL BUMN 2022__BUKU PSIKOTES.txt', '18'),
    ('14f47d77061e3b478bd7eb6715cc178757fe07cf', 'TIU', 'logika-analitis', 'sedang', 'published', 'Sepeda motor berjalan dengan kecepatan 60 km/jam. Jarak yang harus ditempuh adalah 420 km. Waktu tempuh sepeda motor tersebut untuk sampai di tempat tujuan adalah ...', '7 jam', '8 jam', '9 jam', '5 jam', '6 jam', 'D', 'KISI-KISI SOAL BUMN 2022__BUKU PSIKOTES.txt', '20'),
    ('d612b73456d433af07b3f30c823ab48f107d354f', 'TIU', 'aritmetika', 'sedang', 'published', 'Dina menyimpan uang di sebuah bank swasta sebesar Rp500.000,00. Setelah satu tahun, tabungan Dina menjadi Rp540.000,00. Berapa persenkah bunga bank yang diperoleh Dina?', '10%', '50%', '15%', '8%', '5%', 'E', 'KISI-KISI SOAL BUMN 2022__BUKU PSIKOTES.txt', '21'),
