    ('b2769d8cadaec28f07af9e0c3e09df11be070122', 'TIU', 'logika-analitis', 'sedang', 'published', 'Jika 4log 3 = a dan 4log 2 = b, maka 4log 24 = ...', '1 + a + 2b', '2 + a + 2b', '1 + a + b', '3 + a + b', '1 + 2a + b 153Paket Drilling Soal, Tes Kemampuan Numerik', 'E', 'KISI-KISI SOAL BUMN 2022__BUKU PSIKOTES.txt', '34'),
