    ('dbf14be70c067c1ee69c99931543cc6138dca720', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Jika x-y = 1. Dan Xy = 64. Mana pernyataan yang benar berikut ini ?', 'x = y -1', 'x = y64', 'x > y', 'x = 64y', 'y = 1/64x', null, 'KISI-KISI SOAL BUMN 2022__TPA dengan Kunci Jawaban (BUMN).txt', '51'),
    ('c226e00a70ab9f3aaac0a435eb74076335c1c25f', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Nilai m = 4 dan n = -4. Jika p = (-m-n)9 dan q = (- n+n)2 Maka yang benar adalah...', 'p = q', 'p > q', 'p – q = -8', 'q – p = 64', 'q < (p-64)', null, 'KISI-KISI SOAL BUMN 2022__TPA dengan Kunci Jawaban (BUMN).txt', '52'),
    ('5685fe854001182cd3af02cd262f3d33733496be', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Jika m = (7/2) p2 + 9. Dan n = (5/2) p2 + 4. Maka pernyataan yang benar adalah...', 'm > n', 'm < n 44', 'm – p = n', 'p = m + n', 'm + n + p < 0', null, 'KISI-KISI SOAL BUMN 2022__TPA dengan Kunci Jawaban (BUMN).txt', '53'),
    ('844870aea3ad3d65b723a329f309ebd5711b2929', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Jika (x2/2) = 18 dan y = 6. Maka pernyataan yang benar adalah...', 'x = y', 'x < y', 'x dan y tak bisa ditentukan', 'x –y = 1', 'x/y = -1', null, 'KISI-KISI SOAL BUMN 2022__TPA dengan Kunci Jawaban (BUMN).txt', '54'),
    ('f0a658fcde736fa4e01bce6a71c05a98face1975', 'TIU', 'logika-analitis', 'sedang', 'published', 'Jika 7 < a < 12 Dan 8 < b < 13 Maka pernyataan yang benar adalah...', 'a dan b tak bisa ditentukan', 'a pasti lebih besar dari b', 'b pasti lebih besar dai a', 'a – b = -1', 'b = a + 1', 'A', 'KISI-KISI SOAL BUMN 2022__TPA dengan Kunci Jawaban (BUMN).txt', '55'),
    ('d549be84a1478c8a075a87872cbb4ae0b6ce0eb2', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Jika x = 21875 – (2/3) 21875 Dan y = 21875/3 Maka pernyataan yang benar...', 'x dan y tak bisa ditentukan', 'x – y = 0', 'x > y', 'y > x', 'x/y = 1/3', null, 'KISI-KISI SOAL BUMN 2022__TPA dengan Kunci Jawaban (BUMN).txt', '56'),
    ('b2f8d610b92deb5d3dc10671a7a3a184f7c47f59', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Sebuah bujur sangkar panjang sisinya adalah 8. Jika x = 3/2 keliling. Dan y = 2/3 luas. Maka pernyataan yang benar adalah...', 'y = x 45', 'y < x', 'x/y = 1/2', 'y –x = bilangan positif', 'x dan y tak bisa ditentukan', null, 'KISI-KISI SOAL BUMN 2022__TPA dengan Kunci Jawaban (BUMN).txt', '57'),
    ('84d6c0dc54ba022c950972c95c87072351a49d6c', 'TIU', 'logika-analitis', 'sedang', 'draft', 'x adalah 19,95% dari 77. Dan y = 77% dari 19,95. Maka pernyataan yang benar...', 'x dan y nilainya sama', 'x – y = bilangan negatif', 'x /y = 1/77', 'y > x', 'y = x + 1/19,95', null, 'KISI-KISI SOAL BUMN 2022__TPA dengan Kunci Jawaban (BUMN).txt', '58'),
    ('25f0874831ad4c8d0990653fedb198c8c220499f', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Persamaan x (p+q) + xr nilainya sama dengan persamaan berikut, kecuali :', 'xp + xr + xq', 'x (p+q+r)', 'x (p+r) + xq', 'xp + x (q+r)', 'xp (q+r)', null, 'KISI-KISI SOAL BUMN 2022__TPA dengan Kunci Jawaban (BUMN).txt', '59'),
    ('e94ed3691bf2b2abf220c4f30258b0e2005ec79c', 'TIU', 'logika-analitis', 'sedang', 'draft', 'x adalah jumlah derajat segitiga sama sisi dibagi 4. Dan y adalah derajat salah satu sisi dikalikan 1/2. Maka pernyataan yang benar adalah...', 'x-y = 0', '2y – 3/2 x = 0', 'x dan y tak bisa ditentukan', '2x = 3y', 'y > x Tes angka dalam cerita 46', null, 'KISI-KISI SOAL BUMN 2022__TPA dengan Kunci Jawaban (BUMN).txt', '60'),
    ('19e11931d5bbf281e200ebb7c8ad8d5a045f18d5', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Jika Eko bisa membaca 2 halaman koran tiap x menit. Maka dalam 7 menit eko mampu membaca berapa halaman ?', '14/2x', '14/x', 'x/14', '7/2x', '7/x', null, 'KISI-KISI SOAL BUMN 2022__TPA dengan Kunci Jawaban (BUMN).txt', '61'),
    ('1bb46c92b57b46c379c2a9c76a9566abae03ddfe', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Natsir mendapat nilai 81 untuk IPA . Nilai 89 untuk IPS. Nilai 78 untuk Bhs Indonesia. Dan nilai 86 untuk Matematika. Bila natsir ingin mendapatkan rata-rata nilainya sebesar 84. Maka berapakah nilai yang harus diperoleh untuk pelajaran Bahasa Inggris ?', '88', '85', '86', '84', '90', null, 'KISI-KISI SOAL BUMN 2022__TPA dengan Kunci Jawaban (BUMN).txt', '62'),
    ('ac31fd39133a0f7fb0dac10a4a992d0aef0cd802', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Bela membeli baju dengan harga terdiskon 15% dari Rp.80.000,-. Setelah itu karena bela sedang berulang tahun, dia mendapat diskon tambahan sebesar 25% dari harga awal setelah dikurangi diskon 15% diatas. Berapakah harga yang harus dibayarkan oleh Bela ke kasir ?', 'Rp. 48.000', 'Rp. 51.000', 'Rp. 50.000', 'Rp. 55.000', 'Rp. 41.000,- 47', null, 'KISI-KISI SOAL BUMN 2022__TPA dengan Kunci Jawaban (BUMN).txt', '63'),
    ('425530276fd07ac8e65260779497d9cc6fdc3c5c', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Ridho harus mengkredit sebuah laptop dengan lima kali cicilan. Jika uang mukanya sebesar Rp. 1.500.000,- yang merupakan 30% dari harga laptop, berapa rupiahkah yang harus dibayarkan Ridho tiap kali cicilan ?', 'Rp. 750.000', 'Rp. 800.000', 'Rp. 850.000', 'Rp. 710.000', 'Rp. 700.000', null, 'KISI-KISI SOAL BUMN 2022__TPA dengan Kunci Jawaban (BUMN).txt', '64'),
    ('0e14c4d2b11053096b2d9ca500cbdba88e3df5a3', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Didik adalah seorang tukang cat kerajinan papan catur. Dalam 5 menit dia mampu mengecat 25% dari papan berwarna hitam. Berapa lamakah dia mengecat sampai selesai keseluruhan papan catur ? (Keterangan: sebuah papan catur terdiri dari 64 kotak)', '20 menit', '40 menit', '50 menit', '80 menit', '30 menit', null, 'KISI-KISI SOAL BUMN 2022__TPA dengan Kunci Jawaban (BUMN).txt', '65'),
    ('9ecb65a3ff2067012bcdf4058fc47665eec366a0', 'TIU', 'logika-analitis', 'sedang', 'draft', 'tahun lebih tua dari Nia. Nur 2 tahun lebih tua dari Nanik. Dan bila usia mereka dijumlah akan mendapatkan angka 95. Berapakah usia Nia sekarang ?', '26', '35', '15', '24', '25 48', null, 'KISI-KISI SOAL BUMN 2022__TPA dengan Kunci Jawaban (BUMN).txt', '9'),
    ('975725debb6e7da354764363cb91100dcca69af4', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Jika Alamsyah sang juragan lobster mampu menjual lobsternya seharga Rp. 260.000 per ekor, dia mampu mendapatkan keuntungan sebesar 30% dari harga beli awalnya. Jadi, berapakah harga beli awal lobster Alamsyah tersebut ?', 'Rp. 190.000', 'Rp. 200.000', 'Rp. 210.000', 'Rp. 220.000', 'Rp. 230.000', null, 'KISI-KISI SOAL BUMN 2022__TPA dengan Kunci Jawaban (BUMN).txt', '67'),
    ('08e1687ee79462579beed925d55829a9123881be', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Dani memiliki 18 kelereng di kantong. 7 warna kuning. 5 warna biru. Dan 6 warna merah. Berapakah jumlah minimum yang harus diambil dani untuk memastikan bahwa dia mendapatkan setidaknya 1 kelereng untuk tiap warna ?', '13', '12', '7', '15', '14', null, 'KISI-KISI SOAL BUMN 2022__TPA dengan Kunci Jawaban (BUMN).txt', '68'),
    ('6548b692d3b228eea57c5ac327ff7626bae69aa9', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Rovie berangkat ke kota Z pukul 15.35 dengan mengendarai sepeda motor. Rata-rata kecepatannya adalah 32 km/ 30 menit. Jarak perjalanan adalah 80 km. Rovie tiba di kota Z pukul 17.15. Jadi berapa menitkah Rovie berhenti di jalan untuk istirahat ?', '25 menit', '20 menit', '35 menit', '10 menit', '15 menit 49', null, 'KISI-KISI SOAL BUMN 2022__TPA dengan Kunci Jawaban (BUMN).txt', '69'),
    ('6c67a41ecec50c52f5e8225f2e54b6e32da4b622', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Pak Hakim mempunyai sejumlah x kelereng dan dibagikan merata kepada n orang. Setiap orang mendapatkan masing-masing 12 kelereng. Bila ada dua orang yang bergabung untuk minta kebagian kelereng, dan kemudian x kelereng tersebut dibagikan merata, maka tiap orang mendapat 8 kelereng saja. Berapa jumlah n (kelompok pertama) ? Dan berapa pula x (jumlah kelereng) ?', 'n = 2 orang x = 48 kelereng', 'n = 8 orang x = 48 kelereng', 'n = 6 orang x = 44 kelereng', 'n = 4 orang x = 48 kelereng', 'n = 5 orang x = 44 kelereng', null, 'KISI-KISI SOAL BUMN 2022__TPA dengan Kunci Jawaban (BUMN).txt', '70'),
    ('046d92f50294df8e5c496a62a8d3735475a7e8bc', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Luas permukaan kubus bersisi 3 satuan adalah 2 kali luas sebuah persegi panjang bersisi panjang 9 satuan. Berapa satuankah sisi pendek dari persegi panjang ini ?', '4', '2', '3', '6', '5', null, 'KISI-KISI SOAL BUMN 2022__TPA dengan Kunci Jawaban (BUMN).txt', '71'),
    ('3680ad76007b92566dbe9c9bb60079db12f4dce3', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Sebuah survei sampling melaporkan bahwa dalam 1000 kelahiran bayi, 4 diantaranya meninggal. Di kota', '740', '710', '700 50', '720', '705', null, 'KISI-KISI SOAL BUMN 2022__TPA dengan Kunci Jawaban (BUMN).txt', '72'),
    ('6d4d74b624739201f59c327a07133f1acb3c5ce3', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Lia mampu mengerjakan pekerjaan x dalam 30 hari. Ida mampu mengerjakannya dalam 10 hari. Iza mampu mengerjakannya dalam 15 hari. Jika mereka bertiga bergabung untuk mengerjakan pekerjaan x bersama-sama, maka berapa harikah pekerjaan itu dapat diselesaikan ?', '4 hari', '6 hari', '5 hari', '7 hari', '8 hari', null, 'KISI-KISI SOAL BUMN 2022__TPA dengan Kunci Jawaban (BUMN).txt', '73'),
    ('63d76b3157abdca16964543057c0aec9ae6377bc', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Volume ember jika penuh adalah 42,5 liter. Namun hanya terisi 3/5 saja saat ini. Dan diambil lagi oleh Andi sehingga kini hanya terisi 1/5 saja. Berapa literkah yang diambil oleh Andi ?', '17 liter', '8,5 liter', '17,5 liter', '8 liter', '34 liter', null, 'KISI-KISI SOAL BUMN 2022__TPA dengan Kunci Jawaban (BUMN).txt', '74'),
    ('b5cba4e7c32f24239d1beb1aacd09045dc37e5b4', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Fahry dan Popa masing-masing mampu menghabiskan segelas jus apukat dalam waktu 25 detik. Sedangkan Azkia membutuhkan waktu 50 detik untuk melakukan hal sama. Jika ketiganya diminta bergabung untuk menghabiskan 4 ½ gelas jus apukat bersama-sama, berapa lama waktu yang dibutuhkan ? Tapi, Azkia tidak mau bergabung untuk gelas keempat dan gelas kelima. 51', '54 detik', '48,75 detik', '47,85 detik', '50,25 detik', '55 detik', null, 'KISI-KISI SOAL BUMN 2022__TPA dengan Kunci Jawaban (BUMN).txt', '75'),
    ('7a6d9a087fa0da91abadb41a6de4fc979eae6309', 'TIU', 'silogisme', 'sedang', 'draft', 'Kemal berjalan lurus kearah barat ke rumah syaiful sejauh 6km. Lalu ke rumah fifi lurus keutara sejauh 8km. Bila Kemal langsung berjalan lurus ke rumah fifi tanpa pergi kerumah syaiful, berapa km dia dapat menghemat lintasan ? (Catatan: semua lintasan adalah lurus).', '8 km', '6 km', '1 km', '2 km', '4 km Tes Logika (38 Soal, 25 Menit) Tes Logika Umum', null, 'KISI-KISI SOAL BUMN 2022__TPA dengan Kunci Jawaban (BUMN).txt', '76'),
    ('932a20dc375332d93ea467f657ad3f356f20622e', 'TWK', 'wawasan-kebangsaan', 'sedang', 'draft', 'Perilaku Toleran terhadap Keberagaman Sosial Budaya Tidak memandang rendah suku atau budaya yang lain Tidak menganggap suku dan budayanya paling tinggi dan paling baik. Menerima keragaman suku bangsa dan budaya sebagai kekayaan bangsa yang tak ternilai harganya. Lebih mengutamakan Negara daripada kepentingan daerah atau suku masing-masing. Mengetahui keanekaragaman budaya yang dimiliki bangsa Indonesia; Mempelajari dan menguasai salah satu seni budaya sesuai dengan minat dan kesenangannya; Merasa bangga terhadap budaya bangsa sendiri; Menyaring budaya asing yang masuk ke dalam bangsa Indonesia Sumber: beritasatu.com HALAMAN 53 TES WAWASAN KEBANGSAAN BINA TARUNA WIRATAMA BIMBEL BTW www.btw.co.id Bhinneka Tunggal Ika adalah semboyan Negara sebagai modal untuk bersatu. Kemajemukan bangsa merupakan kekayaan kita, kekuatan kita, yang sekaligus juga menjadi tantangan bagi kita bangsa Indonesia, baik kini maupun yang akan datang. Negara Kesatuan Republik Indo- nesia merupakan bentuk Negara yang dipilih sebagai komitmen bersama. Negara Kesatuan Republik Indonesia adalah pilihan yang tepat untuk mewadahi kemajemukan bangsa. Oleh karena itu komitmen kebangsaan akan keutuhan Negara Kesatuan Republik Indonesia menjadi suatu “keniscayaan” yang harus dipaha- mi oleh seluruh komponen bangsa. Dalam Pasal 37 ayat (5) secara tegas menyatakan bahwa khusus mengenai bentuk Negara Kesatuan Republik Indonesia tidak dapat dilakukan perubahan karena merupakan landasan hukum yang kuat bahwa Negara Kesatuan Republik Indonesia tidak dapat diganggu gugat. ideologi dan dasar Negara kedudukannya berada di atas tiga pilar yang lain. Pancasila sebagai ideologi dan dasar Negara harus menjadi jiwa yang menginspirasi seluruh pengaturan kehidupan ber- masyarakat, berbangsa, dan bernegara. Nilai-nilai Pancasila baik sebagai ideologi dan dasar Negara sampai hari ini tetap kokoh menjadi landasan dalam bernegara. Pancasila juga tetap tercantum dalam konstitusi Negara kita meskipun beberapa kali mengalami pergantian dan perubahan konstitusi. Ini menunjukan bahwa Pancasila merupakan konsensus nasional dan dapat diterima oleh semua kelompok masyarakat Indone- sia. Pancasila terbukti mampu memberi kekuatan kepada bangsa Indonesia, sehingga perlu dimaknai, direnungkan, dan diingat oleh seluruh komponen bangsa. Undang-Undang Dasar Negara Republik Indonesia Tahun 1945 adalah konstitusi Negara sebagai landasan konstitusional bangsa Indonesia yang menjadi hukum dasar bagi setiap pera- turan perundang-undangan di bawahnya. Oleh karena itu, dalam Negara yang menganut paham konstitusional tidak ada satupun perilaku penyelenggara Negara dan masyarakat yang tidak berlandaskan konstitusi. “ Bangunlah suatu dunia di mana semua bangsa hidup dalam damai dan persaudaraan - Ir. Soekarno Sumber: dictio.id C HALAMAN 54 TES WAWASAN KEBANGSAAN BINA TARUNA WIRATAMA BIMBEL BTW www.btw.co.id Oleh karena itu kemajemukan itu harus kita hargai, kita junjung tinggi, kita terima dan kita hormati serta kita wujudkan dalam semboyan Bhinneka Tunggal Ika. Majelis Permusyawaratan Rakyat (MPR) sebagai penjelmaan seluruh rakyat Indonesia, memiliki tanggung jawab untuk men- gukuhkan nilai-nilai fundamental kehidupan berbangsa dan bernegara, sesuai dengan mandat konstitusional yang diem- bannya. Dalam kaitan ini, MPR melaksanakan tugas- tugas kon- stitusionalnya dengan menjungjung tinggi nilai-nilai luhur bangsa. Salah satu upaya yang dilakukan MPR adalah dengan melaksanakan tugas untuk memberikan suatu pemahaman nilai-nilai luhur bangsa yang terdapat pada Pancasila, Un- dang-Undang Dasar Negara Republik Indonesia Tahun 1945, Negara Kesatuan Republik Indonesia, dan Bhinneka Tunggal Ika kepada masyarakat. Terbentuknya Empat Pilar Kehidupan Berbangsa dan Bernega- ra untuk mengingatkan kembali komitmen seluruh komponen bangsa agar melaksanakan dan penyelenggaraan kehidupan berbangsa dan bernegara selalu menjungjung tinggi nilai-nilai luhur bangsa dalam rangka mewujudkan Negara Indonesia yang merdeka, bersatu, berdaulat, adil, dan makmur. Sebagai tombak untuk tetap kokohnya berdirinya bangsa Menginspirasi rakyat Indonesia untuk kembali ke rev- olusi atau tujuan yang benar Menjaga kemurnian UUD 1945 Membangun kepahaman tentang jiwa bangsa secara utuh Membangun karakter bangsa Membentuk watak dan peradaban bangsa yang berm- artabat dalam rangka mencerdaskan kehidupan bangsa Sarana pembangunan hukum bangsa Sarana pembaharuan masyarakat Sebagai landasan hidup bermasyarakat, berbangsa dan bernegara Alat ketertiban dan pengaturan masyarakat Setia dan cinta tanah air Mengembangkan persatuan dan kesatuan atas dasar Bhinneka Tunggal Ika Tidak menjadi koruptor Fungsi 4 Pilar Kebangsaan', 'Pengertian Radikalisme Berdasarkan hasil penelitian ditemukan sekurang-kurangnya ada 3 faktor munculnya radikalisme di Indonesia, yakni: perkembangan di tingkat global, penyebaran paham Wahabisme dan kemiskinan. Situa- si yang kacau di negara-negara Timur Tengah khususnya di Afghanistan, Palestina, Irak, Yaman, Mesir, Syiria, dan Turki, dipandang oleh kelompok radikal sebagai akibat dari campur tangan Amerika, Israel, dan sekutunya. Pada saat yang sama, masuknya faham Waha- bisme yang mengagungkan budaya Islam ala Arab yang konser- vatif ke Indonesia telah ikut mendorong timbulnya kelompok eksklu- sif yang sering menuduh orang lain yang berada di luar kelompok mereka sebagai musuh, kaﬁr dan boleh diperangi. Faktor ketiga adalah kemiskinan. Walaupun faktor ini tidak secara langsung berpen- garuh terhadap merebaknya aksi radikalisme, namun perasaan sebagai elemen masyarakat yang termarjinalkan dapat menjadi faktor pendorong bagi seseorang untuk terjebak dalam proganda radikalisme. Radikalisme berasal dari bahasa Latin radix yang berarti akar. Radika- lisme mengandung pegerntian berpikir secara mendalam terhadap sesuatu sampai ke akar-akarnya. Radikalisme merupakan istilah yang digunakan pada akhir abad ke-18 untuk pendukung gerakan radikal. Radikalisme merupakan suatu paham yang menghendaki adanya perubahan, pergantian, dan penjebolan terhadap suatu sistem di mas- yarakat sampai ke akarnya. HALAMAN 65 TES WAWASAN KEBANGSAAN BINA TARUNA WIRATAMA BIMBEL BTW www.btw.co.id Sumber: news.detik.com BAB 06RADIKALISME MATERI TAMBAHAN Bimbel BTW Have the courage to choose your own path, not the path others expect you. - The Futur “ mampu menjadi warga negara yang menghindari paham radikalisme TUJUAN DALAM SKD Menurut Kamus Besar Bahasa Indonesia, yang dimaksud dengan radikalisme adalah paham atau aliran yang radikal dalam politik; paham atau aliran yang menginginkan perubahan atau pembaharuan sosial dan politik dengan cara kekerasan atau drastis; sikap ekstrem dalam politik. Dilihat dari sudut pandang keagamaan, radikalisme agama dapat diartikan sebagai paham keagamaan yang mengacu pada fondasi agama yang sangat mendasar dengan fanatisme keag- amaan yang sangat tinggi, sehingga tidak jarang penganut dari paham atau aliran tersebut menggunakan kekerasan kepada orang yang berbeda paham atau aliran untuk mengaktual- isasikan paham keagamaan yang dianut dan dipercayainya untuk diterima secara paksa. Berdasarkan pengertian radikalisme tersebut, maka tak dapat dihindari adanya kesan negatif dari gerakan radikalisme, yaitu adanya unsur paksaan dan mungkin juga tindakan kekerasan dalam upaya mengaktualisasikannya. Dalam kontek ini, barang- kali dapat dikatakan bahwa sebenarnya tidak ada agama apa pun yang mengajarkan radikalisme. HALAMAN 66 TES WAWASAN KEBANGSAAN BINA TARUNA WIRATAMA BIMBEL BTW www.btw.co.id Faktor Pemikiran Pada masa sekarang muncul dua pemikiran yang menjadi trend, yang pertama yaitu mereka menentang terhadap keadaan alam yang tidak dapat ditolerir lagi, seakan alam ini tidak mendapat keberkahan lagi dari Allah SWT lagi, penuh dengan penyimpangan. Sehingga satu-satunya jalan adalah dengan mengembalikannya kepada agama. Namun jalan yang mereka tempuh untuk mengembalikan ke agama itu ditempuh dengan jalan yang keras dan kaku. Padahal nabi Muhammad SAW selalu memperingatkan kita agar tidak terjebak pada tindakan ekstremisme (at-tatharuf al-diniy), berlebihan (ghuluw), berpaham sempit (dhayy- iq), kaku (tanathu’/rigid), dan keras (tasyaddud). Pemikiran yang kedua yaitu bahwa agama adalah penye- bab kemunduran umat Islam, sehingga jika mereka ingin unggul maka mereka harus meninggalkan agama yang mereka miliki saat ini. Pemikiran ini merupakan hasil dari pemikiran sekularisme, yaitu dimana paham atau pandan- gan ﬁlsafat yang berpendirian bahwa moralitas tidak perlu didasarkan atas pada ajaran agama. Faktor Ekonomi Kemiskinan, pengangguran dan problematika ekonomi yang lain dapat merubah sifat seseorang yang baik menja- di orang yang kejam. Karena dalam keadaan terdesak atau himpitan ekonomi, apapun bisa mereka lakukan, bisa saja', 'Faktor-Faktor Penyebab Radikalisme HALAMAN 67 TES WAWASAN KEBANGSAAN BINA TARUNA WIRATAMA BIMBEL BTW www.btw.co.id Faktor Politik Memiliki pemimpin yang adil, memihak kepada rakyat, dan tidak hanya sekedar menjanjikan kemakmuran kepada rakyatnya adalah impian semua warga masyarakat. Namun jika pemimpin itu mennggunakan politik yang hanya berpi- hak pada pemilik modal, kekuatan-kekuatan asing, bahkan politik pembodohan rakyat, maka akan timbul kelom- pok-kelompok masyarakat yang akan menamakan dirinya sebagai penegak keadilan, baik kelompok dari sosial, agama maupun politik, yang mana kelomok-kelompok tersebut dapat saling menghancurkan satu sama lain. Sep- erti halnya golongan khawarij yang lahir pada masa kholo- fah Ali bin Abi Tholib yang disebabkan oleh ketidak stabi- lan politik pada masa itu, sehingga muncullah golongan syi’a dan khawarij yang meresa paling benar sendiri. Faktor Sosial Faktor sosial ini masih ada hubungannya dengan faktor ekonomi. Ekonomi masyarakat yang amat rendah membuat mereka berﬁkir sempit, dan akhirnya mereka mencari per- lindungan kepada ulama yang radikal, kerena mereka bera- sumsi akan mendapat perubahan perekonomian yang lebih baik. Dimulai dari situ masyarakat sudah bercerai berai, banyak golongan-golongan Islam yang radikal. Sehingga citra Islam yang seharusnya sebagai agama penyejuk dan lembut itu hilang. Disinilah tugas kita untu mengembalikan Islam yang seharusnya sebagai “rohmatallil alamin” agar saudara muslim kita yang tadinya sedikit bergeser tidak semakin bergeser dan kembali kepada akidah-akidah dan syari’ah Islam yang sebenarnya. Faktor Pendidikan Pendidikan bukanlah faktor yang langsung menyebabkan radikalisme. Radikalisme dapat terjadi dikarenakan melalui pendidikan yang salah. Terutama adalah pendidikan agama yang sangat sensitif, kerena pendidikan agama “amal ma’ruf nahi munkar”, namun dengan pendidikan yang salah akan berubah menjadi “amal munkar”. Dan tidak sedikit orang-orang yang terlibat dalam aksi terorisme justru dari kalangan yang berlatar pendidikan umum, seperti dokter, insinyur, ahli teknik, ahli sains, namun hanya mempelajari mereka juga melakukan teror. Mereka juga berasumsi bah- wasannya perputaran ekonomi hanya dirasakan oleh yang kaya saja, hal itu menyebabkan semakin curamnya jurang kemiskinan bagi orang tak punya. Sehingga mereka tidak segan-segan melakukan hal-hal yang diluar dugaan kita. Sebagaimana hadist nabi “kefakiran dapat menyeret kita kepada kekaﬁran”.', 'Radikalisme di Indonesia Secara historis, kemunculan kelom- pok radikal di kalangan umat Islam Indonesia bukanlah hal yang baru. Karena pada awal abad ke-20, dalam peningkatan semangat dan ekonomi kian parah di kalangan pribumi, radikalisme muslim diambil alih oleh kelompok Serikat Islam (SI). Gerakan radikalisme di Indone- sia7 tidak seperti yang terjadi di Timur tengah yang sangat me- nekankan agenda-agenda politik. Gerakan radikal Islam di Indonesia baru sebatas pada tuntutan dipenuhinya aspirasi Islam, seperti pemberlakuan syariat Islam atau piagam Jakarta. Pada era demokratisasi dan masa-masa kebebasan, beberapa kelompok radikal ini untuk muncul lebih nyata, lebih militan dan lebih vokal, ditambah lagi dengan liputan media, khususnya media elektronik, sehingga pada akhirnya gerakan ini lebih tampak. Setelah DI, muncul Komando Jihad (Komji) pada 1976 kemudian meledakkan tempat ibadah. Pada 1977, Front Pembe- basan Muslim Indonesia melakukan hal sama. Dan tindakan teror oleh Pola Perjuangan Revolusioner Islam, 1978. Tidak lama kemudian, setelah pasca reformasi muncul lagi gerakan HALAMAN 68 TES WAWASAN KEBANGSAAN BINA TARUNA WIRATAMA BIMBEL BTW www.btw.co.id Faktor Pendidikan Pengalaman seseorang yang mengalami kepahitan dalam hidupnya, seperti kegagalan dalam karier, permasalahan keluarga, tekanan batin, kebencian dan dendam. Hal-hal tersebut dapat mendorong seseorang untuk berbuat peny- impangan dan anarkis. Kita yang seharusnya senantiasa mengingatkan kepada mereka dari penyimpangan. Dr. Ab- durrahman al-Mathrudi pernah menulis, bahwa sebagian besar orang yang bergabung kepada kelompok garis keras adalah mereka yang secara pribadi mengalami kegagalan dalam hidup dan pendidikannya. saudara muslim kita yang seperti itulah yang menjadi target sasaran orang radikal untuk diajak bergabung dengan mereka. Karena dalam keadaan seperti itu mereka sangat rentan dan mudah ter- pengaruh. agama sedikit dari luar sekolah, yang kebenaran pemaha- mananya belum tentu dapat dipertanggungjawabkan. Atau dididik oleh kelompok Islam yang keras dan memiliki pemahaman agama yang serabutan. Sumber: kompasiana.com yang beraroma radikal yang dipimpin oleh Azhari & Nurdin M. Top dan gerakan-gerakan radikal lainnya yang bertebar di beberapa wilayah Indonesia, seperti Poso, Ambon dan yang lainnya. Semangat radikalisme tentu tidak luput dari persoalan politik. Persoalan politik memang sering kali menimbulkan geja- la-gejala tindakan yang radikal sehingga berakibat pada kenya- manan umat beragama yang ada di Indonesia dari berbagai rag- amnya. Dalam konstelasi politik Indonesia, masalah radikalisme Islam makin besar karena pendukungnya juga makin mening- kat. Akan tetapi gerakan-gerakan ini lambat laun berbeda tujuan, serta tidak mempunyai pola yang seragam. Ada yang sekedar memperjuangkan implementasi syari’at Islam tanpa keharusan mendirikan “negara Islam”, namun ada pula yang memperjuangkan berdirinya negara Islam Indonesia, di samping yang memperjuangkan berdirinya “kekhalifahan Islam’, pola organisasinya pun beragam, mulai dari gerakan moral ide- ologi seperti Majelis Mujahidin Indonesia dan Hizbut Tahrir Indonesia (HTI) sampai kepada gaya militer seperti Laskar Jihad, dan FPI. Aksi terorisme di Indonesia saat ini memang tengah menurun sejak awal tahun 2000-an. Namun akar terorisme, yaitu radi- kalisme agama, tetap tumbuh subur dan mendapatkan posisi di sebagian masyarakat. Selain radikalisme agama, aksi terror juga masih berisiko muncul akibat gesekan-gesekan lainnya, seperti anti persatuan, separatisme, dan lain-lain. Oleh karena imunitas harus senantiasa mengingat bahwa kita hidup di Indo- nesia, negeri yang terdiri dari keberagaman. Jika kita tidak bersikap tenggang rasa dan berpikiran terbuka, maka akar-akar radikalisme pun dapat leluasa masuk memengaruhi kita. Pemer- intah juga perlu untuk menjadi lokomotif dalam pembangunan persatuan dan kesejahteraan bangsa guna menghindarkan negeri ini dari ancaman radikalisme yang memanfaatkan cel- ah-celah ketidak adilan. Sementara peneliti LIPI Anas Saidi mengatakan bahwa paham radikalisme ini terjadi karena proses Islamisasi yang dilakukan di kalangan anak muda ini ber- langsung secara tertutup, dan cenderung tidak terbuka pada pandangan Islam lainnya, apalagi yang berbeda keyakinannya. Dia menegaskan jika pemahaman ini dibiarkan bisa menyebab- kan disintegrasi bangsa karena mereka menganggap ideologi pancasila tidak lagi penting. HALAMAN 69 TES WAWASAN KEBANGSAAN BINA TARUNA WIRATAMA BIMBEL BTW www.btw.co.id “ with gun you can kill terrorists, with educa- tion you can kill terrorism - Malala Yousafzai Sumber: monitor.co.id', 'Membendung Berkembangnya Paham Radikalisme Tahun 2011, Hasil Survey Lembaga Kajian Islam dan Perdamaian (LaKIP) dengan responden guru PAI dan siswa SMP Se Jadebo- tabek menunjukkan potensi radikal yang kuat di kalangan guru dan pelajar dengan indikasi resistensi yang lemah terhadap kekerasan atas nama agama, intoleransi, sikap ekslusif serta keraguan terhadap ideologi Pancasila. Meningkatkan Pemahaman Keagamaan Radikalisme disebabkan oleh minimnya pemahaman agama. Belajar agama secara dangkal dapat memicu mereka melakukan kekerasan, bahkan atas nama agama. Tindakan terorisme balakangan ini dilakukan dengan cara bunuh diri, misalnya bom bunuh diri, sebab Islam justru melarang tindakan bunuh diri, sehingga tindakan teror- isme dalam bentuk apapun sangat bertentangan dengan ajaran Islam. Membentuk Komunitas-komunitas Damai di Lingkungan Sekitar Pemuda bisa menjadi pionir dalam pembentukan komuni- tas cinta damai di lingkungannya. Komunitas-komunitas tersebut lah yang melakukan sosialisasi ke masyarakat maupun ke sekolah-sekolah akan bahaya paham radika- lisme. Menyebar Virus damai Didunia Maya Hasil penelitian terbaru mencatat pengguna internet di Indonesia yang berasal dari kalangan anak-anak dan remaja diprediksi mencapai 30 juta. Mereka ini menggu- nakan internet hanya untuk mencari informasi, untuk ter- hubung dengan teman (lama dan baru) dan untuk hiburan. Hal inilah yang menjadi celah bagi para penyebar paham radikalisme untuk menyebarkan pahamnya di dunia maya. Oleh karena itu, dibutuhkan aksi dari pemuda sebagai pengguna internet terbanyak di Indonesia untuk menang- kal informasi-informasi yang menyesatkan dengan men- gunggah konten damai di social media seperti tulisan, komik, dan meme. Menjaga Persatuan dan Kesatuan Generasi muda adalah Warga Negara yang menjadi unsur penting dalam suatu Negara. Menunjukkan sikap bela Negara para Generasi Muda saat ini dapat dilakukan dengan menampilkan perilaku-perilaku positif yang sesuai dengan Pancasila dan UUD 1945 dengan men- junjung tinggi persatuan dan kesatuan bangsa yang bertujuan untuk melawan segala macam paham keben- cian dan kekerasan yang ingin merusak keutuhan NKRI. HALAMAN 70 TES WAWASAN KEBANGSAAN BINA TARUNA WIRATAMA BIMBEL BTW www.btw.co.id HALAMAN 71 TES WAWASAN KEBANGSAAN BINA TARUNA WIRATAMA BIMBEL BTW www.btw.co.id Menimalisis Kesenjangan Sosial Kesenjangan sosial yang terjadi juga dapat memicu mun- culnya pemahaman radikalisme dan tindakan terorisme. Caranya ialah pemerintah harus mampu merangkul pihak media yang menjadi perantaranya dengan rakyat sekaligus melakukan aksi nyata secara langsung kepada rakyat. Begitu pula dengan rakyat, mereka harusnya juga selalu memberikan dukungan dan kepercayaan kepada pihak pemerintah bahwa pemerintah akan mampu menjalankan tugasnya dengan baik sebagai pengayom rakyat dan pemegang kendali pemerintahan Negara. KUNCI SUKSES LULUS SKD Success key #1: PENGAYAAN DAN PENGUASAAN SOAL Success key #2: PEMBIASAAN CAT (Computer Assisted Test) Success key #3: PENGUASAAN STRATEGI OPTIMASI WAKTU HARGA PAKET SOAL SKD DI APLIKASI SKD BIMBEL BTW PAKET A', 'Ciri-Ciri Bahasa Indonesia HALAMAN 59 TES WAWASAN KEBANGSAAN BINA TARUNA WIRATAMA BIMBEL BTW www.btw.co.id Sebagai bahasa resmi kenegaraan, bahasa Indonesia dipakai di dalam berbagai kegiatan kenegaraan, baik dalam bentuk lisan maupun dalam bentuk tulisan. Sebagai bahasa pengantar di dunia pendidikan, bahasa Indonesia digunakan di lembaga-lem- baga pendidikan mulai taman kanak-kanak sampai dengan per- guruan tinggi di seluruh Indonesia, kecuali di daerah-daerah, seperti di Pulau Jawa, daerah Sunda dan Jawa yang menggu- nakan bahasa daerahnya sebagai bahasa pengantar sampai dengan tahun ketiga pendidikan dasar. Sehubungan dengan fungsinya yang ketiga, bahasa Indonesia adalah alat perhubun- gan pada tingkat nasional untuk kepentingan perencanaan dan pelaksanaan pembangunan nasional dan untuk kepentingan pelaksanaan pemerintah. Dalam kedudukannya sebagai bahasa negara, bahasa Indonesia sebagai alat