    ('e49eeafb2de40045b281a763ca542a586a16a5c9', 'TIU', 'logika-analitis', 'sedang', 'published', 'Air : Haus = Uap air : ....', 'Embun', 'Basah', 'Kering', 'Lembab', 'Hangat', 'C', 'SOAL TO 1 + KUNCI JAWABAN__SOAL TKD-TIU.txt', '14'),
    ('ca71ac93106f14e93d99517319baaf66420a86c2', 'TIU', 'logika-analitis', 'sedang', 'published', 'Jika 20 ekor kambing mampu menghabiskan rumput sebanyak 4 lapangan selama 8 hari, maka 16 ekor kambing mampu menghabiskan rumput sebanyak 8 lapangan selama ... hari.', '8', '12', '14', '16', '20', 'E', 'SOAL TO 1 + KUNCI JAWABAN__SOAL TKD-TIU.txt', '15'),
    ('031dd433103f98784b2789a93cdf853b5fb14f10', 'TIU', 'logika-analitis', 'sedang', 'published', '1 kg + 2 Ons + 0,2 kwintal =…. gram', '21200', '22100', '12200', '20120', '21020', 'A', 'SOAL TO 1 + KUNCI JAWABAN__SOAL TKD-TIU.txt', '16'),
    ('ee3ed2a2c4813967a4ffb704358418a8a32b9c10', 'TIU', 'logika-analitis', 'sedang', 'published', '6, 3, 6, 18, 9, 12, 36, ...', '9', '12', '18', '39', '108', 'C', 'SOAL TO 1 + KUNCI JAWABAN__SOAL TKD-TIU.txt', '17'),
    ('eee5dbcf73ad6d058d343215a77077560459abdb', 'TIU', 'logika-analitis', 'sedang', 'published', 'Lima orang bersahabat yaitu Adi, Teti, Moli, Heni, dan Nety menonton film di bioskop. Mereka membeli tiket pada baris A, B, C, D, E, dengan posisi A merupakan baris terdepan. Moli duduk lebih depan dibandingkan Teti. Heni di antara Teti dan Moli. Adi di depan Moli dan Nety tepat di belakang Teti. Dari informasi tersebut yang duduk pada barisan A dan D adalah ....', 'Heni dan Moli', 'Adi dan Nety', 'Adi dan Teti', 'Heni dan Neti', 'Moli dan Teti', 'C', 'SOAL TO 1 + KUNCI JAWABAN__SOAL TKD-TIU.txt', '18'),
    ('0fe854e01864920c738f57f08508d29d3192c7b3', 'TIU', 'logika-analitis', 'sedang', 'published', 'Konvers dari pernyataan "Jika saya mengantuk maka saya akan tidur" adalah...', 'Jika saya tidak mengantuk maka saya tidak akan tidur', 'Jika tidak tidur maka saya tidak mengantuk', 'Jika saya mengantuk maka saya kurang tidur', 'Jika saya akan tidur maka saya mengantuk', 'Jika tidak tidur maka saya akan megantuk', 'D', 'SOAL TO 1 + KUNCI JAWABAN__SOAL TKD-TIU.txt', '19'),
    ('c7330c043ffcda89e9a8aede8b209fb5aed3fd1c', 'TIU', 'logika-analitis', 'sedang', 'published', 'Semua musik memiliki tempo cepat. Beberapa yang memiliki tempo cepat adalah pop.', 'sebagian musik memiliki tempo yang cepat', 'semua musik pop bertempo yang cepat', 'sebagian pop bukan merupakan musik', 'semua musik merupakan pop', 'semua yang bertempo cepat adalah pop', 'C', 'SOAL TO 1 + KUNCI JAWABAN__SOAL TKD-TIU.txt', '20'),
    ('4d54187521f84202279349b33f4d9664b68a2a89', 'TIU', 'logika-analitis', 'sedang', 'published', 'Bila naik kereta api harus membayar kontan atau memakai tiket abonemen. Badu naik kereta api padahal tidak membayar kontan. Simpulan?', 'Badu tidak membayar untuk naik kereta api', 'Badu membayar kontan untuk naik kereta api', 'Badu membayar dengan tiket abonemen', 'Badu tidak mempunyai tiket abonemen', 'Badu tidak mempunyai uang kontan', 'C', 'SOAL TO 1 + KUNCI JAWABAN__SOAL TKD-TIU.txt', '21'),
    ('2108945f14b3ca62ff5ad236e6662012f30530e6', 'TIU', 'logika-analitis', 'sedang', 'published', 'Toni memiliki sebuah rak buku kecil yang terbagi atas lima tingkat, tingkat 1, 2, 3, 4, dan 5. Tingkat 1 adalah yang teratas dan tingkat 5 adalah yang terbawah. Toni menyimpan buku-buku pelajarannya ke dalam rak dengan aturan sebagai berikut:a. Buku pelajaran Geografi disimpan tepat di atas buku pelajaran Matematika, sedangkan buku pelajaran Bahasa Indonesia diletakkan t epat di bawah buku Matematika.b. Buku pelajaran Ekonomi diletakkan di atas buku pelajaran Fisika, sedangkan buku pelajaran Fisika dan Kimia berada di atas buku pelajaran Geografi.c. Buku pelajaran Kimia dan Biologi diletakkan saling terpisah sejauh mungkin.Buku yang disimpan tidak berdampingan dengan buku yang lain adalah buku ....', 'Matematika, Bahasa Indonesia, Ekonomi', 'Kimia, Fisika, Biologi', 'Fisika, Matematika, Geografi', 'Bahasa Indonesia, Biologi, Geografi', 'Ekonomi, Kimia, Fisika', 'C', 'SOAL TO 1 + KUNCI JAWABAN__SOAL TKD-TIU.txt', '22'),
    ('13d261e08bebaf4805f61629f9a1aca803097cb2', 'TIU', 'logika-analitis', 'sedang', 'published', '125, 205, 305, 425, 565, 725, ....', '945', '885', '925', '905', '865', 'D', 'SOAL TO 1 + KUNCI JAWABAN__SOAL TKD-TIU.txt', '23'),
    ('9e53d6422aad15ac99256e88e9e529f7b7e0d865', 'TIU', 'logika-analitis', 'sedang', 'published', 'Sebuah pekerjaan dapat dikerjakan oleh 2 orang dalam waktu 2 hari. Jika terdapat 20 orang dan setiap 2 jam bekerja mereka semua beristirahat 15 menit, maka pekerjaan tersebut akan selesai dalam … menit', '368', '288', '303', '333', '318', 'E', 'SOAL TO 1 + KUNCI JAWABAN__SOAL TKD-TIU.txt', '24'),
    ('40863d1211806db41d426e2c483ea1c9cde9f072', 'TIU', 'logika-analitis', 'sedang', 'published', '33, 34, 36, 40, 48, ....', '60', '54', '72', '58', '64', 'E', 'SOAL TO 1 + KUNCI JAWABAN__SOAL TKD-TIU.txt', '25'),
    ('af904f152e655dbb03391b7f13d915746bbd323f', 'TIU', 'logika-analitis', 'sedang', 'published', 'Jika kakek membaca koran di ruang tamu, maka kakek tidak menggunakan kacamatanya. Jika kakek tidak menggunakan kacamatanya, maka kakek akan kesulitan membaca. Pagi ini kakek tidak menggunakan kacamatanya. Kesimpulan mana yang benar?', 'Kakek membaca di ruang tamu.', 'Pagi ini kakek membaca koran.', 'Kakek tidak bisa membaca koran.', 'Kakek tidak membaca koran pagi ini.', 'Pagi ini kakek akan kesulitan membaca.', 'E', 'SOAL TO 1 + KUNCI JAWABAN__SOAL TKD-TIU.txt', '26'),
    ('e864ef66ea4d576dc11c710e7993bccac6557bf1', 'TIU', 'logika-analitis', 'sedang', 'published', 'Pak Drajad berbelanja dengan menggunakan mobil yang memiliki daya angkut 750 kg. Pak Drajad membeli 3 kuintal gula dan 7 karung beras yang masing -masing karung beras beratnya 50kg. Berat maksimal tepung terigu yang dapat dibelinya?', '100 kg', '50 kg', '75 kg', '115 kg', '125 kg', 'A', 'SOAL TO 1 + KUNCI JAWABAN__SOAL TKD-TIU.txt', '27'),
