    ('5f00ba0e53720b8c44f10ac06c92e78b7a3a2347', 'TIU', 'logika-analitis', 'sedang', 'published', 'Nilai ujian Rian termasuk urutan 16 dari atas dan juga urutan 16 dari bawah dalam kelasnya. Berapa banyak siswa yang berada di dalam kelas Rian?', '30 orang', '16 orang', '31 orang', '32 orang', '26 orang', 'C', 'SOAL TO 1 + KUNCI JAWABAN__SOAL TKD-TIU.txt', '31'),
    ('6ddfa93b202942eb6d5162133c257bc46afb3286', 'TIU', 'logika-analitis', 'sedang', 'published', 'liter lagi, bejana itu akan berisi air kira-kira nya. Berapa literkah kapasitas bejana itu?', '15 liter', '18 liter', '24 liter', '27 liter', '30 liter', 'D', 'SOAL TO 1 + KUNCI JAWABAN__SOAL TKD-TIU.txt', '3'),
