    ('8a2e4340e57bc4aff815942f8373a2575ff519d3', 'TWK', 'wawasan-kebangsaan', 'sedang', 'draft', 'Tata urutan perundang- undangan menurut TAP MPR No III/ MPR/ 2000 adalah', 'UU Perpu, Peraturan Pemerintah,,Keppres, Peraturan Daerah', 'UUD 1945, TAP MPR, Peraturan Pemerintah, Undang- Undang, UU Perpu,Keppres, Peraturan Daerah', 'UUD 1945, TAP MPR, Peraturan Pemerintah, Undang- Undang, Kepres, UU Perpu, Peraturan Daerah', 'UUD 1945, TAP MPR,UU Perpu, Undang- Undang, Peraturan Pemerintah,Keppres, Peraturan Daerah', 'UUD 1945, TAP MPR, Peraturan Pemerintah, Undang- Undang, UU Perpu,, Keppres, Peraturan Daerah', null, 'SOAL TO 1 + KUNCI JAWABAN__SOAL TKD-TWK.txt', '39'),
    ('3a8dbae77a8080d4f736742b9ab99a0b19adbeff', 'TWK', 'wawasan-kebangsaan', 'sedang', 'draft', 'Pada tanggal 22 Juni 1945 Panitia Sembilan mengadakan sidang dan menghasilkan keputusan yang lebih dikenal Piagam Jakarta (Jakarta Charter), istilah ini dimunculkan oleh :', 'Ir. Soekarno', 'Mr. Moh Yamin', 'Muhamad Hatta', 'Radjiman Wideodiningrat', 'K.H Mansur', null, 'SOAL TO 1 + KUNCI JAWABAN__SOAL TKD-TWK.txt', '40'),
