    ('134991db646f296ed3b88a55834480b53ec20f92', 'TWK', 'wawasan-kebangsaan', 'sedang', 'published', 'Sistem ekonomi kolonial di Indonesia disebut system liberal (1870 – 1900) disebut ekonomi liberal, maksudnya adalah …', 'Pada waktu itu modal swasta diberi peluang sepenuhnya untuk mengusahakan kegiatan di Indonesia', 'Ketentuan besarnya pajak tanah ditentukan oleh luas tanah yang dimiliki oleh masing-masing petani', 'Petani diberi kebebasan untuk menanam apa saja di tanahnya', 'Pemerintah mengambil semua perkebunan tanaman ekspor', 'Pengusaha-pengusaha modal swasta tidak diizinkan memiliki perkebunan ekspor', 'D', 'TWK+PEMBAHASAN.txt', '12'),
    ('e152ef002310f7c5493d542861fd9a3a498618ba', 'TWK', 'wawasan-kebangsaan', 'sedang', 'published', 'Hal-hal di bawah ini yang berkaitan dengan pembentukan Verenigde Oost Indische Compagnie (VOC), kecuali …', 'Jumlah direktur adalah 17 orang yang disebut dengan Heeren XVII', 'VOC memperoleh hak octrooi dan parlemen', 'Markas besar VOC ditempatkan di Rotterdam', 'VOC memiliki wewenang memiliki mata uang sendiri', 'VOC berhak memiliki tentara sendiri', 'B', 'TWK+PEMBAHASAN.txt', '13'),
    ('8d5a9d1ffa2e8eebd8fe4694892a898fe31aa4da', 'TWK', 'wawasan-kebangsaan', 'sedang', 'published', 'Keberhasilan VOC menguasai perdagangan di Kepulauan Indonesia pada dasarnya bukan semata-mata karena keunggulan system dan teknologi perkapalannya melainkan karena melakukan intrik-intrik di kalangan raja -raja setempat, misalnya antara …', 'Sultan Antasari melawan Muhammad Syah', 'Sultan Iskandar muda melawan Iskandar Tani', 'Sultan Khairun melawan Baabulah', 'Sultan Agung melawan para bupati di pesisir', 'Betul semua', 'C', 'TWK+PEMBAHASAN.txt', '14'),
    ('a71e9ff460f4e5cf93265fb2a4bb10fbb27cad3d', 'TWK', 'wawasan-kebangsaan', 'sedang', 'published', 'Yang termasuk penyebab kemunduran VOC adalah … 61', 'VOC mengalami surplus keuangan', 'Hasil ekspor yang semakin menurun', 'Banyaknya anggota VOC yang korupsi', 'Anggaran untuk pegawai terlalu kecil', 'Sesuai dengan semangat liberalisme dalam ekonomi', 'A', 'TWK+PEMBAHASAN.txt', '15'),
    ('940bacbbf63400167845e1dea306ed35fedacfda', 'TWK', 'wawasan-kebangsaan', 'sedang', 'published', 'Dalam sengketa Indonesia-Belanda, Australia muncul sebagai pihak ketiga dalam Komisi Tiga Negara. Dua negara yang lain adalah …', 'Swedia, Amerika Serikat', 'Belgia, Amerika Serikat', 'Cina, Amerika Serikat', 'Austria, Amerika Serikat', 'Cina, Inggris', 'D', 'TWK+PEMBAHASAN.txt', '16'),
    ('c316b73869467a873fb63c69fbe3a39408bf10f2', 'TWK', 'wawasan-kebangsaan', 'sedang', 'published', 'Tujuan dibentuknya BPUPKI adalah', 'Untuk mempalajari hal -hal yang penting mengenai masalah tata pemerintahan Indonesia Merdeka', 'Merumuskan Dasar Filsafat Negara', 'Mempersiapkan Proklamasi Kemerdekaan Indonesia', 'Menyusun Pembentu kan Negara Kesatuan Republik Indonesia', 'Merumuskan tujuan Dasar Negara Indonesia', 'D', 'TWK+PEMBAHASAN.txt', '17'),
    ('fd97ddfdcc5900ab61ba3fbeb7a12a2aed2b260b', 'TWK', 'wawasan-kebangsaan', 'sedang', 'published', 'Tujuan dibentuknya Panitia Persiapan Kemerdekaan Indonesia adalah …', 'Merumuskan dasar Negara', 'Mempersiapkan proklamasi kemerdekaan', 'Membentuk kabinet', 'Mempersiapkan masalah ketatanegaraan', 'Mempersatukan seluruh potensi rakyat', 'B', 'TWK+PEMBAHASAN.txt', '18'),
    ('e38eef64cfa3a9bc39f715ab5e674cd1d51732ee', 'TWK', 'wawasan-kebangsaan', 'sedang', 'published', 'BPUPKI yang dibentuk oleh Komakichi Harada diketuai oleh …', 'Ir. Soekarno', 'Moh. Hatta', 'Dr. Radjiman Widyodiningrat', 'Ahmad Subarjo', 'Moh. Yamin', 'C', 'TWK+PEMBAHASAN.txt', '19'),
    ('51c645e5c371d916bdb25cc688c404dacb20a7a8', 'TWK', 'wawasan-kebangsaan', 'sedang', 'published', 'Latar belakang dikeluarkannya Dekrit Presiden 5 Juli 1959 adalah …', 'Parlemen terlalu kuat', 'Dominasi PKI', 'Konstituante belum berhasil membuat konstitusi baru', 'Kehidupan ekonomi Indonesia terbengkalai', 'Instabilitas dalam bidang politik', 'D', 'TWK+PEMBAHASAN.txt', '20'),
    ('fcd2f65599023c3b451a8b0fcbf023203b2feeab', 'TWK', 'wawasan-kebangsaan', 'sedang', 'published', 'Perjanjian antara Indonesia -Belanda pada masa mempertahankan Republik Proklamasi, yang mengh asilkan pengakuan de fakto RIS terhadap Jawa, Madura dan Sumatra ialah …', 'Perjanjian Linggarjati', 'Perjanjian Renvile', 'Perjanjian Balibo', 'KMB', 'Konferensi Den Haag', 'E', 'TWK+PEMBAHASAN.txt', '21'),
    ('0da0b080b9046c83c405e080649c301c952272c7', 'TWK', 'wawasan-kebangsaan', 'sedang', 'published', 'Pada masa kabinet Ali Sastroamidjojo I telah diupayakan dengan system ekonomi baru yang disebut system Ali Baba. Tujuannya adalah …', 'Memajukan pengusaha pribumi', 'Memajukan Pengusa non-pribumi', 'Meningkatkan peranan pengusaha nonpribumi dan pribumi', 'Meningkatkan hubungan perdagangan dengan Belanda', 'Meningkatkan hubungan dagang dengan Cina', 'C', 'TWK+PEMBAHASAN.txt', '22'),
    ('82f17b4ba83e0625ad2bf1dd49f60641e2a02d56', 'TWK', 'wawasan-kebangsaan', 'sedang', 'published', 'RIS yang terdiri atas Negara -negara bagian dan kesatuan kenegaraan yang disetujui oleh KMB mulai goyah. Hal ini disebabkan oleh beberapa faktor, kecuali …', 'Eksistensinya sangat tergantung pada militer Belanda', 'Tokoh-tokoh menterinya sebagian beraliran liberalis', 'Tokoh-tokoh m enteri yang terkemuka sebagian besar beraliran republikan.', 'Tidak mendapat dukungan rakyat', 'Dasar pembentukannya tidak didukung oleh suatu ikatan ideology yang kuat', 'A', 'TWK+PEMBAHASAN.txt', '23'),
    ('75bae88b28cf73d2d711a54ca59750d03ceb2bf8', 'TWK', 'wawasan-kebangsaan', 'sedang', 'published', 'Raffless yang menjadi Gubernur Inggris di Indonesia (1811 – 1816) mengadakan beberapa perubahan, antara lain perubahan dalam bidang ekonomi seperti …', 'Penyerahan hasil bumi', 'Kerja paksa atau rodi dikurangi', 'Pemerintah menjadi pemilik seluruh tanah dan yang menggarap tanah harus membayar sewa', 'Pengusaha pribumi memperoleh kembali kekuasaan untuk mengatur pajak wilayahnya', 'Rakyat diharuskan menanam tanaman yang telah ditentukan oleh pihak penguasa kolonial', 'A', 'TWK+PEMBAHASAN.txt', '24'),
    ('ae7cff5db769a4e7700622e2a09d0f98547e5a3e', 'TWK', 'wawasan-kebangsaan', 'sedang', 'published', 'Sultan Agung, raja Mataram menyerang Batavia pada tahun 1628, tetapi gagal dan salah satu faktor penyebabnya adalah … 62', 'Pasukan Belanda jumlahnya lebih banyak', 'Gugurnya Tumenggung Wiroguno', 'Benteng Hollandia di Batavia sangat kokoh', 'Kekurangan bahan makan', 'Angkatan Laut Mataram lemah', 'B', 'TWK+PEMBAHASAN.txt', '25'),
    ('da1831d3d9337f600329ad6a58643b1476202115', 'TWK', 'wawasan-kebangsaan', 'sedang', 'published', 'Propaganda pemerintah Jepang di Indonesia dikenal dengan gerakan 3A. Pada tahun 1943, gerakan ini dirubah menjadi Puter a dan beranggotakan tokoh -tokoh pergerakan nasional di bawah ini, kecuali …', 'Soekarno', 'Ki Hajar Dewantoro', 'Muhammad Yamin', 'Ki Haji Mas Mansyur', 'Muhammad Hatta', 'E', 'TWK+PEMBAHASAN.txt', '26'),
    ('cc9e9d22ad6be875ca2b585c05e32abdb06bd27b', 'TWK', 'wawasan-kebangsaan', 'sedang', 'published', 'Karena Jepang semakin terdesak oleh Sekutu yang dipimpin oleh Mc.Arthur, maka usaha Jepang agar tidak kehilangan muka, Jepang memberi janji kemerdekaan di kelak kemudian hari untuk Indonesia dengan melakukan langkah sebagai berikut …', 'Bahasa Belanda dipakai sebagai bahasa pergaulan', 'Diperbolehkan partai-partai politik', 'Dibiarkannya rakyat menyusun kekuatan militer', 'Membiarkan sekutu masuk lagi Indonesia', 'Memperbolehkan dikibarkannya bendera dan lagu Indonesia Raya dinyanyikan', 'A', 'TWK+PEMBAHASAN.txt', '27'),
    ('f66d9ef4c7f49662a3c45784aedf0b6dc4ce6c29', 'TWK', 'wawasan-kebangsaan', 'sedang', 'published', 'Upaya yang dilakukan pemerintah setelah peristiwa Proklamasi 17 Agustus 1945 adalah menata stabilitas nasional dengan berdasarkan system pemerintahan sebagai berikut …', 'Sistem Presidensil', 'Sistem Parlementer', 'Sistem Federal', 'Sistem Uni Indonesia-Belanda', 'Sistem Republik', 'C', 'TWK+PEMBAHASAN.txt', '28'),
    ('edfc4cb5e4a050686ab392a26315aec5d1b1e947', 'TWK', 'wawasan-kebangsaan', 'sedang', 'published', 'Sidang Panitia Persiapan Kemerdekaan Indonesia (PPKI) pada tanggal 18 Agustus 1945 telah menghasilkan keputusan penting bagi kehidupan kenegaraan Indonesia, yaitu …', 'Pengesahan UUD 1945', 'Penetapan anggota PPKI', 'Pembubaran BPUPKI', 'Persetujuan anti penjajahan', 'Penggantian anggota PPKI', 'A', 'TWK+PEMBAHASAN.txt', '29'),
    ('a42cee291a2f25f01d0ebbb35fc49c9c5ff05a96', 'TWK', 'wawasan-kebangsaan', 'sedang', 'published', 'Salah satu hasil kesepakatan antara wakil - wakil RI dengan pimpinan sekutu yaitu Brigjen A.W.S. Mallaby adalah …', 'Tentara Indonesia akan melakukan kerja sama dengan sekutu dalam melucuti tentara Jepang', 'Tentara sekutu berhak mendapatkan perlakuan khusus dari pemerintah Indonesia', 'Akan segera dibentuk Kontak Biro agar kerjasama dapat terlaksana', 'Pemerintah Indonesia akan menjamin keselamatan bagi AFNEI', 'Pemerintah Indonesia harus menghormati NICA sebagai bagian dari tentara sekutu', 'C', 'TWK+PEMBAHASAN.txt', '30'),
    ('9ac590b2c4fed040be976194ecf705d476985713', 'TWK', 'wawasan-kebangsaan', 'sedang', 'published', 'OKI (Organisasi Konferensi Islam) yang berdiri pada tahun 1969 merupakan sebuah reaksi tidak langsung atas tindakan …', 'Serbia terhadap masyarakat Bosnia', 'Amerika terhadap Taliban Afganistan', 'Yahudi Israel yang membakar Masjid Al - Aqsa', 'Amerika terhadap Iran', 'Amerika terhadap Lybia Petunjuk B', 'A', 'TWK+PEMBAHASAN.txt', '31'),
    ('01c9095c44953b1d4b890f832fdc9544dc081f1c', 'TWK', 'wawasan-kebangsaan', 'sedang', 'published', 'Penulisan nama dan gelar berikut ini yang benar adalah :', 'Prof. Dr. Sumaryono, SE', 'Prof. Dr. Sumaryono; SE', 'Prof. Dr. Sumaryono, SE.', 'Prof. Dr. Sumaryono, S.E.', 'Prof. Dr. Sumaryono, S.E', 'D', 'TWK+PEMBAHASAN.txt', '5'),
    ('0a44d8c9ee44bae7d9af8a6f951fafbf7c4eeea8', 'TWK', 'wawasan-kebangsaan', 'sedang', 'published', 'Penulisan kata serapan yang tepat terdapat dalam kalimat …', 'Setiap rumah sebaiknya memiliki apotek hidup.', 'Para atlit menerima wejangan dari pelatih.', 'Kami mendengarkan santapan rokhani setiap pagi.', 'Agar bentuknya seragam harus distandarisir. 67', 'Uang transport yang kami terima tidak memadai.', 'B', 'TWK+PEMBAHASAN.txt', '18'),
    ('103b7a690d211a99467a0055364a8282e0bbe100', 'TWK', 'wawasan-kebangsaan', 'sedang', 'published', 'Dulu kami tidak pernah kebanjiran, tetapi kini setiap hujan lebat air pasti menggenangi rumah kami. Kata kebanjiran dalam kalimat itu termasuk golongan …', 'benda', 'kata kerja', 'kata sifat', 'kata keadaan', 'kata keterangan', 'C', 'TWK+PEMBAHASAN.txt', '19'),
    ('cb63e92c484febb984c580d12bcd2782aa3f02ae', 'TWK', 'wawasan-kebangsaan', 'sedang', 'published', 'Penggunaan kata bilangan tingkat dalam kalimat-kalimat berikut yang benar adalah …', 'Ketiga perusahaan itu sudah berdiri sejak lima tahun yang lalu.', 'Kepala sekolah memberi penghargaan kepada kedua pemenang lomba itu.', 'Percetakan itu memerlukan tiga orang penyuting.', 'Dia merupakan karyawan kelima ya ng di-PHK.', 'Kedua puluh pedagang itu mendapatkan pinjaman dari bank.', 'D', 'TWK+PEMBAHASAN.txt', '20'),
    ('21c0e57625076e4218f3422a9d009ad2735f7b6a', 'TWK', 'wawasan-kebangsaan', 'sedang', 'published', 'Mulailah menjaga kesehatan dengan memperhatikan sanitasi. Makna kata sanitasi adalah …', 'kebutuhan vitamin dalam tubuh', 'keseimbangan jasmani dan rohani', 'kekebalan tubuh', 'kebutuhan cairan dalam tubuh', 'kesehatan lingkungan', 'E', 'TWK+PEMBAHASAN.txt', '21'),
    ('34e7535c73fe50a61c7efdebfa38ec678437d5f7', 'TWK', 'wawasan-kebangsaan', 'sedang', 'published', 'Kalau sedang berjalan janganlah membiasakan menjual mata. Makna ungkapan menjual mata dalam kalimat di atas adalah …', 'mencari perhatian', 'memperagakan diri', 'melihat ke sana ke sini', 'suka berlagak', 'menyombongkan diri', 'C', 'TWK+PEMBAHASAN.txt', '22'),
    ('b85f7e91f00bf096a66cec79dc53d9cdc7539747', 'TWK', 'wawasan-kebangsaan', 'sedang', 'published', 'Kereta api tua dengan wajah kusam terengah- engah di terik matahari melengking menjerit seakan tidak kuasa lagi membawa beban. Kalimat di atas menggunakan majas …', 'hiperbola', 'personifikasi', 'metafora', 'litotes', 'sinisme', 'A', 'TWK+PEMBAHASAN.txt', '23'),
    ('24dba9b706e1460c4bceb7bb34ff2d9e75e4b987', 'TWK', 'wawasan-kebangsaan', 'sedang', 'published', 'Lebih baik tenang dan sabar daripada ribut serta marah. Kata dalam pernyataan di atas yang bermakna leksikal, adalah…', 'lebih', 'dan', 'daripada', 'baik', 'serta', 'A', 'TWK+PEMBAHASAN.txt', '24'),
    ('f50227adef3e21a817204be6205e3b7371ab7935', 'TWK', 'wawasan-kebangsaan', 'sedang', 'published', 'Pak Handoko memperbaiki atap teras rumahnya yang sudah bocor. Makna gramatikal kata memperbaiki pada kalimat di atas adalah …', 'benefaktif', 'refleksif', 'kausatif', 'intensitas', 'resiprok', 'B', 'TWK+PEMBAHASAN.txt', '25'),
    ('379bfe0874b9e46524d27a086cb8f6a2da4037ff', 'TWK', 'wawasan-kebangsaan', 'sedang', 'published', 'Kata naik yang bermakna denotatif terdapat dalam kalimat …', 'Kalau harga barang -barang sudah naik tidak mungkin turun lagi.', 'Si Basir tidak naik kelas karena jarang masuk sekolah.', 'Karena jasa -jasanya, pangkatnya dinaikkan satu tingkat.', 'Artis kondang itu sedang naik daun.', 'Dia naik kereta api jurusan Surabaya.', 'E', 'TWK+PEMBAHASAN.txt', '26'),
    ('ea3d883795ac6b01e7f6c7f57c32d91286a2fa34', 'TWK', 'wawasan-kebangsaan', 'sedang', 'published', 'Kalimat di bawah ini yang menggunakan kata yang mengalami perluasan makna adalah …', 'Ibuku sedang menyelesaikan tugas akhir S2-nya di ITS.', 'Terima kasih atas perhatian Saudara selama ini.', 'Pak Ebo diangkat menjadi pengurus yayasan bersama saudaranya.', 'Ia sering termenung sendirian sejak ditinggal bapaknya.', 'Bapak dan ibuku kemarin mengajakku ke Bandung. 68', 'C', 'TWK+PEMBAHASAN.txt', '28'),
    ('f6b0df2265a557c1a243087b84b9249dbcae037e', 'TWK', 'wawasan-kebangsaan', 'sedang', 'published', 'Kata sedap yang bermakna sinestesia terdapat dalam kalimat …', 'Makanan ini terasa sangat sedap.', 'Bunga sedam malam tumbuh di halaman rumahku.', 'Bumbu penyedap makanan itu mahal harganya.', 'Kata-kata orang itu kurang sedap didengar.', 'Sayur buatan ibu sangat sedap.', 'A', 'TWK+PEMBAHASAN.txt', '29'),
    ('7c68893d50b5bf7b2aa4c60ea71ed3b09fb79390', 'TWK', 'wawasan-kebangsaan', 'sedang', 'draft', 'Kata bilangan berawalan ke yang menyatakan kumpulan terdapat pada kalimat …', 'Dalam sidang pengadilan, Jaksa menghadirkan saksi ketiga.', 'Hadiah kedua lomba baca puisi diberikan kepada Waluyo.', 'Ketiga pencuri itu terah ditangkap polisi.', 'Hingga hari keempat, penelitiannya belum selesai.', 'Dalam rapat itu kelompok kami duduk pada deretan kursi kelompok. KUNCI JAWABAN DAN PEMBAHASAN BAHASA INDONESIA', 'C', 'TWK+PEMBAHASAN.txt', '30'),
    ('9da694f7862195c236fb894fc28f81690e89d96c', 'TIU', 'logika-analitis', 'sedang', 'draft', 'PINDAI = ....', 'MELIHAT SEKILAS', 'MENCERMATI', 'MELIRIK', 'MEMBUANG', 'MEMINDAHKAN Pembahasan: TRIK! Perbanyak perbendaharaan Bahasa Indonesia dengan sering membaca Kamus Besar Bahasa Indonesia (KBBI) dan membaca buku/artikel. Kata PINDAI memiliki arti ‘melihat dengan cermat dan lama’. Jadi, kata yang bersinonim dengan PINDAI adalah MENCERMATI. Jawaban: B', null, 'All New Tes CPNS 2019-2020 - Garuda Eduka.txt', '2'),
    ('a1b580b35ee30b7a86c385dbd3dc9fc0d0b997dd', 'TIU', 'logika-analitis', 'sedang', 'draft', 'BIMBANG = ....', 'PASRAH', 'FLEKSIBEL', 'PERCAYA', 'YAKIN', 'RAGU-RAGU Pembahasan: TRIK! Cari tahu arti katanya karena bisa jadi sinonimnya terdapat pada arti kata. Kata bimbang memiliki arti ‘tidak tetap hati (kurang percaya); ragu-ragu’. Jadi, kata yang bersinonim dengan BIMBANG adalah RAGU-RAGU. Jawaban: E TIP DAN TRIK:', null, 'All New Tes CPNS 2019-2020 - Garuda Eduka.txt', '5'),
    ('a951e0d6aa1efdf0c7531d9f756480662ba227dd', 'TIU', 'logika-analitis', 'sedang', 'draft', 'Antonim gradual Antonim gradual merupakan antonim yang memiliki tingkatan dalam pertentangan. Contoh: rumah mewah > < rumah sederhana CONTOH SOAL: te AKI 2S sxe', 'BERAKAL', 'PANDAI', 'LEMAH', 'BODOH', 'CERDIK Pembahasan: TRIK! Untuk kata yang tidak biasa digunakan kehidupan sehari-hari, cermati pilihan jawabannya. Pilihlah kata yang BERBEDA dari semua pilihan yang ada. AKIL memiliki arti ‘berakal; cerdik; pandai’. Kata BERAKAL, CERDIK, dan PANDAI memiliki arti yang sama dengan AKIL, sedangkan kata LEMAH memiliki arti yang tidak sesuai dengan kata AKIL. Jadi, lawan kata AKIL adalah BODOH. Jawaban: D', null, 'All New Tes CPNS 2019-2020 - Garuda Eduka.txt', '5'),
    ('a3d2d4f668fb6fe5abc57c4f9e8835e2db4ad8d3', 'TIU', 'logika-analitis', 'sedang', 'draft', 'EKSPOR >< ....', 'PENGIRIMAN', 'PEMBELIAN', 'LUAR NEGERI', 'BARANG', 'IMPOR Pembahasan: TRIK! Lawan kata EKS (KELUAR) adalah IM (DALAM). EKSPOR memiliki arti ‘pengiriman barang dagangan ke luar negeri’. Jadi, lawan kata EKSPOR adalah IMPOR yang memiliki arti ‘pemasukan barang dari luar negeri’. Jawaban: E', null, 'All New Tes CPNS 2019-2020 - Garuda Eduka.txt', '2'),
    ('e33e26706f13c8d414dba95085642f40859b5cdc', 'TIU', 'logika-analitis', 'sedang', 'draft', 'RAPUH ><.....', 'TEGAR', 'KUKUH', 'KOYAK', 'RENTAN', 'KUAT Pembahasan: TRIK! Jika ada dua atau lebih pilihan jawaban yang memungkinkan, pilih salah satu setelah menelaah arti kata pada soal. RAPUH memiliki arti ‘sudah rusak (patah, pecah, sobek putus)’. e@ ~~ TEGAR memiliki arti ‘keras dan kering; keras kaku’. ¢ KUAT memiliki arti ‘tahan; tidak mudah goyah; ketat; erat’. e KUKUH memiliki arti ‘kuat terpancang pada tempatnya; tidak mudah roboh atau rusak; teguh’. Jadi, lawan kata yang tepat dari RAPUH adalah KUKUH. Jawaban: B', null, 'All New Tes CPNS 2019-2020 - Garuda Eduka.txt', '3'),
    ('6537c22526df5bc9286025fe1eae677b071e9c91', 'TIU', 'logika-analitis', 'sedang', 'draft', 'ANGGARA > <....', 'JINAK', 'LIAR', 'HALUS', 'MALU', 'BUAS Pembahasan: TRIK! Untuk kata yang tidak biasa digunakan kehidupan sehari-hari, ARTIKAN KATANYA terlebih dahulu lalu cari lawan katanya. ANGGARA memiliki arti ‘buas; liar’. Kata BUAS dan LIAR memiliki arti yang sama dengang ANGGARA, sedangkan MALU dan HALUS memiliki arti kata yang tidak berhubungan dengan ANGGARA. Jadi, lawan kata ANGGARA adalah JINAK. Jawaban: A TIP DAN TRIK:', null, 'All New Tes CPNS 2019-2020 - Garuda Eduka.txt', '4'),
    ('038274944157ca7bf5d04f8d8c69638d705712d4', 'TIU', 'logika-analitis', 'sedang', 'draft', 'MANIS: LIDAH = JALAN :....', 'KAKI', 'JEMBATAN PENYEBERANGAN', 'SEPATU', 'JARING', 'TROTOAR Pembahasan: Jenis padanan hubungan: “fungsi” MANIS dapat dirasakan oleh LIDAH dan JALAN dapat dilakukan oleh KAKI. Jawaban: A', null, 'All New Tes CPNS 2019-2020 - Garuda Eduka.txt', '1'),
    ('c3760a6fe3590bbb1cb4d1f9d971b15dfebc8890', 'TIU', 'logika-analitis', 'sedang', 'draft', 'PIRAMID: MESIR = ...:....', 'BOROBUDUR : INDONESIA.', 'CANDI: KOTA', 'KAIRO : TIMUR TENGAH', 'PRASASTI : LINGGA', 'CINA: BARONGSAI Pembahasan: Jenis padanan hubungan: “asosiasi” PIRAMID merupakan keajaiban duniayangterdapatdi MESIRdan BOROBUDUR merupakan keajaiban dunia yang terdapat di INDONESIA. Jawaban: A', null, 'All New Tes CPNS 2019-2020 - Garuda Eduka.txt', '2'),
    ('c1148e504f3eb73ed1c36a890099feff63360ac9', 'TIU', 'logika-analitis', 'sedang', 'draft', 'BERUDU:... = LARVA:....', 'KATAK MUDA : KERPOMPONG', 'KECEBONG : PUPA', 'TELUR : DAUN', 'PERUBAHAN : PERKEMBANGAN', 'IKAN : KUPU-KUPU Pembahasan: Jenis padanan hubungan: “derajat” Setelah BERUDU, metamorfosis pada katak selanjutnya adalah KATAK MUDA dan setelah LARVA, metamorfosis pada katak selanjutnya adalah KEPOMPONG. Jawaban: A TIP DAN TRIK:', null, 'All New Tes CPNS 2019-2020 - Garuda Eduka.txt', '3')
  ) as q(hash, category_code, topic_slug, difficulty, status, question_text, option_a, option_b, option_c, option_d, option_e, answer_label, source_file, source_number)
), inserted_questions as (
  insert into questions (category_id, topic_id, question_text, explanation, difficulty, status, source_type, source_url, license, attribution, generated_by_ai, published_at)
  select c.id, t.id, q.question_text, null, q.difficulty, q.status, 'pdf_extract', q.source_file || '#soal-' || q.source_number, 'review_required', q.source_file, false, case when q.status = 'published' then now() else null end
  from extracted_questions q
  join categories c on c.code = q.category_code
  join topics t on t.category_id = c.id and t.slug = q.topic_slug
  where not exists (select 1 from questions existing where existing.question_text = q.question_text)
  returning id, question_text
), option_rows as (
  select iq.id as question_id, q.category_code, q.answer_label, option_data.label, option_data.option_text
  from inserted_questions iq
  join extracted_questions q on q.question_text = iq.question_text
  cross join lateral (values
    ('A', q.option_a), ('B', q.option_b), ('C', q.option_c), ('D', q.option_d), ('E', q.option_e)
  ) as option_data(label, option_text)
)
insert into question_options (question_id, label, option_text, is_correct, score)
select question_id, label, option_text, label = answer_label,
  case when category_code in ('TWK','TIU') and label = answer_label then 5 when category_code in ('TWK','TIU') then 0 when category_code = 'TKP' and label = answer_label then 5 else 1 end
from option_rows
on conflict (question_id, label) do nothing;

commit;
